fn page_mark_entry_stream_byte_offset(page_mark: &DocumentPageMark, entry_index: usize) -> usize {
    12 + page_mark
        .entries()
        .iter()
        .take(entry_index)
        .map(DocumentPageMarkEntry::raw_len)
        .sum::<usize>()
}

