// RFC 0007 §PaperMark: flag 0x00010011 appears exclusively in Ginga vertical-writing
// samples (a5/a6/b6/46) and never in horizontal samples. Not yet formally decoded
// (TODO 327), so the result is diagnostic-only and must not gate WritingMode directly.
fn writing_mode_from_document_view_styles(styles: &[UnknownStyle]) -> WritingMode {
    let has_record_0x1001 = styles
        .iter()
        .filter(|style| style.name() == Some(DOCUMENT_VIEW_STYLES_PATH))
        .any(|style| {
            summarize_style_stream(style.payload())
                .records()
                .first()
                .map(|r| r.code() == 0x1001)
                .unwrap_or(false)
        });
    if has_record_0x1001 {
        WritingMode::VerticalRl
    } else {
        WritingMode::Horizontal
    }
}

fn writing_mode_candidate_from_paper_marks(
    paper_marks: &[DocumentPaperMark],
) -> Option<WritingMode> {
    let has_vertical_flag = paper_marks.iter().any(|mark| {
        mark.entries()
            .iter()
            .any(|entry| entry.flags() == 0x0001_0011)
    });
    if has_vertical_flag {
        Some(WritingMode::VerticalRl)
    } else {
        None
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct StyleCandidate {
    id: u32,
    name: String,
    source_stream: String,
    source_record_index: usize,
    source_offset: usize,
    source_code: u16,
    payload_len: usize,
}

fn text_style_candidates(styles: &[UnknownStyle]) -> Vec<StyleCandidate> {
    let mut candidates = Vec::new();

    for style in styles {
        if style.name() != Some(TEXT_LAYOUT_STYLE_PATH) {
            continue;
        }

        let summary = summarize_style_stream(style.payload());
        for (record_index, record) in summary.records().iter().enumerate() {
            let Some(label) = record.label() else {
                continue;
            };
            let trimmed = label.trim();
            if trimmed.is_empty() {
                continue;
            }

            candidates.push(StyleCandidate {
                id: candidates.len() as u32 + 1,
                name: trimmed.to_string(),
                source_stream: TEXT_LAYOUT_STYLE_PATH.to_string(),
                source_record_index: record_index,
                source_offset: record.offset(),
                source_code: record.code(),
                payload_len: record.payload_len(),
            });
        }
    }

    candidates
}

