    output.push_str(",\"blockCount\":");
    output.push_str(&projection.block_count.to_string());
    output.push_str(",\"layoutRecordCount\":");
    output.push_str(&projection.layout_record_count.to_string());
    output.push_str(",\"positionTablePresent\":");
