fn push_page_layer_source_span_json(
    output: &mut String,
    source_id: usize,
    fragment: &PageLayerTextFragment,
) {
    output.push_str(&format!(
        "{{\"id\":{},\"utf8Range\":{},\"utf16Range\":{}",
        source_id,
        source_range_json(0, fragment.text.len()),
        source_range_json(0, fragment.text.encode_utf16().count())
    ));
    if let Some(paragraph_index) = fragment.paragraph_index {
        output.push_str(",\"stableSourceKey\":");
        output.push_str(&json_string(&format!(
            "section:0/para:{paragraph_index}/char:{}",
            fragment.char_start
        )));
    }
    if let Some(span) = &fragment.source_span {
        output.push_str(",\"jtdByteRange\":");
        output.push_str(&source_range_json(span.byte_start(), span.byte_end()));
        output.push_str(",\"jtdUnitRange\":");
        output.push_str(&source_range_json(span.unit_start(), span.unit_end()));
    }
    output.push('}');
}

fn source_range_json(start: usize, end: usize) -> String {
    format!("{{\"start\":{start},\"end\":{end}}}")
}

fn page_text_line_fragments(
    document: &Document,
    line: &PageTextLine,
) -> Vec<PageLayerTextFragment> {
    let Some(paragraph_index) = line.paragraph_index() else {
        return vec![PageLayerTextFragment {
            text: line.text().to_string(),
            paragraph_index: None,
            char_start: line.char_start(),
            char_end: line.char_end(),
            source_span: None,
            ruby_annotation: None,
        }];
    };

    let Some(paragraph) = paragraph_by_index(document, paragraph_index) else {
        return Vec::new();
    };
    let mut fragments = paragraph_line_fragments(
        paragraph,
        paragraph_index,
        line.char_start(),
        line.char_end(),
    );
    let source_text = fragments
        .iter()
        .map(|fragment| fragment.text.as_str())
        .collect::<String>();
    if !source_text.is_empty() && line.text().starts_with(&source_text) {
        let source_len = source_text.chars().count();
        let suffix = line.text().chars().skip(source_len).collect::<String>();
        if !suffix.is_empty() {
            let suffix_len = suffix.chars().count();
            fragments.push(PageLayerTextFragment {
                text: suffix,
                paragraph_index: None,
                char_start: line.char_start() + source_len,
                char_end: line.char_start() + source_len + suffix_len,
                source_span: None,
                ruby_annotation: None,
            });
        }
    }
    fragments
}

fn paragraph_by_index(document: &Document, paragraph_index: usize) -> Option<&Paragraph> {
    document
        .blocks()
        .iter()
        .filter_map(|block| match block {
            Block::Paragraph(paragraph) => Some(paragraph),
            Block::Unknown(_) => None,
        })
        .nth(paragraph_index)
}

fn paragraph_line_fragments(
    paragraph: &Paragraph,
    paragraph_index: usize,
    line_start: usize,
    line_end: usize,
) -> Vec<PageLayerTextFragment> {
    let mut fragments = Vec::new();
    let mut paragraph_offset = 0usize;

    for inline in paragraph.inlines() {
        let (text, source_span, ruby_annotation) = match inline {
            Inline::Text(run) => (run.text(), run.source_span(), None),
            Inline::Ruby(ruby) => (ruby.base_text(), None, Some(ruby.annotation_text())),
            Inline::Unknown(_) => ("", None, None),
        };
        let inline_len = text.chars().count();
        let inline_start = paragraph_offset;
        let inline_end = inline_start + inline_len;
        paragraph_offset = inline_end;

        let overlap_start = inline_start.max(line_start);
        let overlap_end = inline_end.min(line_end);
        if overlap_start >= overlap_end {
            continue;
        }

        let relative_start = overlap_start - inline_start;
        let relative_end = overlap_end - inline_start;
        let annotation = if ruby_annotation.is_some()
            && overlap_start == inline_start
            && overlap_end == inline_end
        {
            ruby_annotation.map(str::to_string)
        } else {
            None
        };
        fragments.push(PageLayerTextFragment {
            text: text_by_char_range(text, relative_start, relative_end),
            paragraph_index: Some(paragraph_index),
            char_start: overlap_start,
            char_end: overlap_end,
            source_span: source_span
                .map(|span| source_span_for_char_range(text, span, relative_start, relative_end)),
            ruby_annotation: annotation,
        });
    }

    fragments
}

fn source_span_for_char_range(
    text: &str,
    source_span: &TextSourceSpan,
    start_chars: usize,
    end_chars: usize,
) -> TextSourceSpan {
    let start_units = utf16_units_before_chars(text, start_chars);
    let end_units = utf16_units_before_chars(text, end_chars);
    source_span.subspan_by_units(start_units, end_units)
}

fn utf16_units_before_chars(text: &str, chars: usize) -> usize {
    text.chars().take(chars).map(char::len_utf16).sum::<usize>()
}

fn text_by_char_range(text: &str, start: usize, end: usize) -> String {
    text.chars().skip(start).take(end - start).collect()
}

fn text_width_px(layout: PageLayout, text: &str) -> f64 {
    text.chars()
        .map(|character| display_column_width(character) as f64 * column_width_px(layout))
        .sum()
}

fn text_width_px_for_font_size(font_size: f32, text: &str) -> f64 {
    text.chars()
        .map(|character| display_column_width(character) as f64 * f64::from(font_size) * 0.55)
        .sum()
}

fn vertical_text_advance_px(text: &str) -> f64 {
    text.chars()
        .map(|character| {
            display_column_width(character) as f64 * APP_VERTICAL_DISPLAY_UNIT_PX as f64
        })
        .sum()
}

fn text_positions_px(layout: PageLayout, text: &str) -> Vec<f64> {
    let mut positions = Vec::new();
    let mut x = 0.0;
    positions.push(x);
    for character in text.chars() {
        x += display_column_width(character) as f64 * column_width_px(layout);
        positions.push(x);
    }
    positions
}

fn text_positions_px_for_font_size(font_size: f32, text: &str) -> Vec<f64> {
    let mut positions = Vec::new();
    let mut x = 0.0;
    positions.push(x);
    for character in text.chars() {
        x += display_column_width(character) as f64 * f64::from(font_size) * 0.55;
        positions.push(x);
    }
    positions
}

fn text_positions_px_for_mode(
    layout: PageLayout,
    writing_mode: WritingMode,
    text: &str,
) -> Vec<f64> {
    if !writing_mode.is_vertical() {
        return text_positions_px(layout, text);
    }

    let mut positions = Vec::new();
    let mut y = 0.0;
    positions.push(y);
    for character in text.chars() {
        y += display_column_width(character) as f64 * APP_VERTICAL_DISPLAY_UNIT_PX as f64;
        positions.push(y);
    }
    positions
}

fn push_f64_array_json(output: &mut String, values: &[f64]) {
    output.push('[');
    for (index, value) in values.iter().enumerate() {
        if index > 0 {
            output.push(',');
        }
        output.push_str(&format!("{value:.3}"));
    }
    output.push(']');
}

fn fallback_text_fill_color(document: &Document, text: &str) -> &'static str {
    if document_has_shanai_lan_fdm_command_evidence(document) {
        shanai_lan_text_fill_color(text).unwrap_or("#111111")
    } else {
        "#111111"
    }
}

fn shanai_lan_text_fill_color(text: &str) -> Option<&'static str> {
    let trimmed = text.trim_matches(|character| character == ' ' || character == '\u{3000}');
    if trimmed.is_empty() {
        return None;
    }
    if trimmed.contains("社内LAN構成図") {
        return Some("#008000");
    }
    if trimmed.contains("ファイルサーバ") || trimmed.contains("ｶﾗｰｼﾞｪｯﾄﾌﾟﾘﾝﾀｰ")
    {
        return Some("#000080");
    }
    None
}

fn shanai_lan_text_fill_basis(document: &Document, text: &str) -> &'static str {
    if !document_has_shanai_lan_fdm_command_evidence(document) {
        return "default-text-fill";
    }
    if shanai_lan_text_fill_color(text).is_some() {
        "shanai-lan-text-match-fallback"
    } else {
        "default-text-fill"
    }
}

fn shanai_lan_text_style_link_evidence(
    document: &Document,
    document_text_bytes: &[u8],
    text_entry: &DocumentTextMapEntry,
    fill_basis: &'static str,
    text_count_range_evidence: &[ShanaiLanTextCountRangeEvidence],
) -> ShanaiLanTextStyleLinkEvidence {
    let text_layout_style_record_count =
        style_stream_record_count(document, TEXT_LAYOUT_STYLE_PATH);
    let document_view_style_group_count = document_view_style_group_count(document);
    let document_view_style_group_candidate =
        shanai_lan_document_view_style_group_candidate(text_count_range_evidence);
    let document_view_style_group_candidate_basis =
        document_view_style_group_candidate.map(|_| "document-text-position-count-tail-field-f7");
    let document_text_group_header_candidate =
        shanai_lan_document_text_group_header_candidate(document_text_bytes, text_entry);
    let document_text_inline_style_candidate =
        shanai_lan_document_text_inline_style_candidate(document_text_bytes, text_entry);
    let fill_color_promotion_blocked_reason = (fill_basis == "shanai-lan-text-match-fallback")
        .then_some("text-match-fallback-not-decoded-style");

    ShanaiLanTextStyleLinkEvidence {
        source: "DocumentText+DocumentTextPositionTables+DocumentViewStyles",
        style_link_proven: false,
        text_layout_style_record_count,
        document_view_style_group_count,
        document_view_style_group_candidate,
        document_view_style_group_candidate_basis,
        document_text_group_header_candidate,
        document_text_inline_style_candidate,
        style_link_promotion_blocked_reason: "document-view-style-group-link-unproven",
        fill_color_promotion_blocked_reason,
    }
}

fn shanai_lan_document_text_group_header_candidate(
    bytes: &[u8],
    entry: &DocumentTextMapEntry,
) -> Option<ShanaiLanDocumentTextGroupHeaderCandidate> {
    let units = document_text_units(bytes);
    let header_start = (0..entry.unit_start()).rev().find(|index| {
        units.get(*index).copied() == Some(0x001c) && units.get(index + 1).copied() == Some(0x0010)
    })?;
    let text_marker_index = (header_start + 2..entry.unit_start())
        .find(|index| units.get(*index).copied() == Some(DOCUMENT_TEXT_TEXT_RUN_MARKER))?;
    let raw_words = units.get(header_start..=text_marker_index)?.to_vec();
    if raw_words.len() < 3 || raw_words.len() > 64 {
        return None;
    }
    let field_words = raw_words
        .get(2..raw_words.len().saturating_sub(1))
        .unwrap_or_default()
        .to_vec();
    let source_span = TextSourceSpan::new(
        header_start * 2,
        (text_marker_index + 1) * 2,
        header_start,
        text_marker_index + 1,
    );
    Some(ShanaiLanDocumentTextGroupHeaderCandidate {
        source_span,
        raw_words,
        field_words,
        distance_to_text_units: entry.unit_start().saturating_sub(text_marker_index + 1),
        promotion_blocked_reason: "document-text-group-header-semantics-unproven",
    })
}

fn shanai_lan_document_text_inline_style_candidate(
    bytes: &[u8],
    entry: &DocumentTextMapEntry,
) -> Option<ShanaiLanDocumentTextInlineStyleCandidate> {
    let units = document_text_units(bytes);
    let text_marker_index = entry.unit_start().checked_sub(1)?;
    if units.get(text_marker_index).copied() != Some(DOCUMENT_TEXT_TEXT_RUN_MARKER) {
        return None;
    }

    let search_start = text_marker_index.saturating_sub(32);
    let inline_end = (search_start..text_marker_index)
        .rev()
        .find(|index| units.get(*index).copied() == Some(0x001e))?;
    let inline_start = (search_start..inline_end)
        .rev()
        .find(|index| units.get(*index).copied() == Some(DOCUMENT_TEXT_INLINE_START_TAG as u16))?;
    let context_start = inline_start.checked_sub(6)?;
    let context_words = units.get(context_start..inline_start)?.to_vec();
    if !shanai_lan_document_text_inline_style_context(&context_words) {
        return None;
    }
    let selector = context_words.get(5).copied();
    let payload_words = units.get(inline_start + 1..inline_end)?.to_vec();
    let post_inline_words = units.get(inline_end + 1..=text_marker_index)?.to_vec();
    let raw_words = units.get(context_start..=text_marker_index)?.to_vec();
    let source_span = TextSourceSpan::new(
        context_start * 2,
        (text_marker_index + 1) * 2,
        context_start,
        text_marker_index + 1,
    );
    let distance_to_text_units = entry.unit_start().saturating_sub(inline_end + 1);

    Some(ShanaiLanDocumentTextInlineStyleCandidate {
        source_span,
        selector,
        context_words,
        payload_words,
        post_inline_words,
        raw_words,
        distance_to_text_units,
        promotion_blocked_reason: "document-text-inline-control-semantics-unproven",
    })
}

fn shanai_lan_document_text_inline_style_context(context_words: &[u16]) -> bool {
    context_words.len() == 6
        && context_words[0] == 0x001c
        && context_words[1] == 0x0001
        && context_words[2] == 0x0007
        && context_words[3] == 0x0000
}

fn document_text_units(bytes: &[u8]) -> Vec<u16> {
    bytes
        .chunks_exact(2)
        .map(|chunk| u16::from_be_bytes([chunk[0], chunk[1]]))
        .collect()
}

fn shanai_lan_document_view_style_group_candidate(
    evidence: &[ShanaiLanTextCountRangeEvidence],
) -> Option<u16> {
    let mut candidate = None;
    for item in evidence {
        let Some(group_id) = item.tail_fields.get(7).copied() else {
            continue;
        };
        if !(1..=9).contains(&group_id) {
            continue;
        }
        match candidate {
            Some(existing) if existing != group_id => return None,
            Some(_) => {}
            None => candidate = Some(group_id),
        }
    }
    candidate
}

fn style_stream_record_count(document: &Document, stream_name: &str) -> usize {
    document
        .unknown_styles()
        .iter()
        .find(|style| style.name() == Some(stream_name))
        .map(|style| summarize_style_stream(style.payload()).records().len())
        .unwrap_or_default()
}

fn document_view_style_group_count(document: &Document) -> usize {
    let Some(style) = document
        .unknown_styles()
        .iter()
        .find(|style| style.name() == Some(DOCUMENT_VIEW_STYLES_PATH))
    else {
        return 0;
    };

    summarize_style_stream(style.payload())
        .records()
        .iter()
        .filter_map(|record| document_view_style_group_id(record.code()))
        .collect::<BTreeSet<_>>()
        .len()
}

fn document_view_style_group_id(code: u16) -> Option<u16> {
    let group_id = code >> 8;
    let record_kind = code & 0x00ff;
    ((0x31..=0x39).contains(&group_id) && (0x04..=0x07).contains(&record_kind))
        .then(|| group_id - 0x30)
}

fn shanai_lan_text_count_range_evidence(
    document: &Document,
    span: &TextSourceSpan,
) -> Vec<ShanaiLanTextCountRangeEvidence> {
    let mut evidence = Vec::new();
    for range in document.text_count_ranges() {
        push_shanai_lan_text_count_range_evidence(
            &mut evidence,
            range,
            TextCountRangeOverlapBasis::Byte,
            span.byte_start(),
            span.byte_end(),
        );
        push_shanai_lan_text_count_range_evidence(
            &mut evidence,
            range,
            TextCountRangeOverlapBasis::Unit,
            span.unit_start(),
            span.unit_end(),
        );
    }
    evidence
}

fn push_shanai_lan_text_count_range_evidence(
    evidence: &mut Vec<ShanaiLanTextCountRangeEvidence>,
    range: &TextCountRange,
    basis: TextCountRangeOverlapBasis,
    span_start: usize,
    span_end: usize,
) {
    let range_start = range.start() as usize;
    let range_end = range.end() as usize;
    let overlap_start = span_start.max(range_start);
    let overlap_end = span_end.min(range_end);
    if overlap_start >= overlap_end {
        return;
    }
    evidence.push(ShanaiLanTextCountRangeEvidence {
        index: range.index(),
        family: range.family().to_string(),
        basis,
        range_start,
        range_end,
        overlap_start,
        overlap_end,
        declared_start: range.declared_start(),
        declared_end: range.declared_end(),
        tail_fields: range.tail_fields().to_vec(),
    });
}

fn fallback_text_origin(layout: PageLayout, document: &Document) -> Option<(f32, f32)> {
    if !document_has_shanai_lan_fdm_command_evidence(document) {
        return None;
    }
    let viewport = fdm_projection_viewport(layout);
    Some((viewport.x, viewport.y))
}

fn shanai_lan_document_text_projection(
    document: &Document,
    layout: PageLayout,
    page_number: usize,
) -> Option<ShanaiLanTextProjection> {
    if page_number != 1 || !document_has_shanai_lan_fdm_command_evidence(document) {
        return None;
    }

    let bytes = document_text_raw_stream(document)?;
    let map = map_document_text(bytes);
    let group_offsets = shanai_lan_text_group_offsets(bytes);
    let max_extent_units = shanai_lan_text_max_extent_units(bytes)
        .unwrap_or(0x0118)
        .saturating_sub(SHANAI_LAN_TEXT_GRID_EXTENT_GUTTER_UNITS)
        .max(1);
    let viewport = fdm_projection_viewport(layout);
    let grid_unit_px = viewport.width / f32::from(max_extent_units);
    let scale_y = layout.height_px() / SHANAI_LAN_REFERENCE_PAGE_HEIGHT_PX;
    let fallback_font_units = 12u16;
    let line_height_px =
        f32::from(fallback_font_units) * SHANAI_LAN_TEXT_GROUP_LINE_HEIGHT_FACTOR * scale_y;
    let mut slots = Vec::new();

    for entry in map
        .entries()
        .iter()
        .filter(|entry| entry.kind() == DocumentTextMapKind::TextRun)
    {
        let fragments = shanai_lan_visible_text_fragments(entry.text());
        if fragments.is_empty() {
            continue;
        }
        let source_span = TextSourceSpan::from_document_text_entry(entry);
        let line_header = shanai_lan_line_header_for_text_entry(bytes, entry);
        let group_index = shanai_lan_group_index_for_text_entry(&group_offsets, entry);
        let leading_units = leading_display_units(entry.text());
        let line_offset_units = line_header
            .as_ref()
            .map(|header| header.offset_units)
            .unwrap_or_default();
        let font_size_units = line_header
            .as_ref()
            .map(|header| header.font_size_units)
            .unwrap_or(fallback_font_units);
        let font_size = f32::from(font_size_units) * SHANAI_LAN_TEXT_FONT_SIZE_SCALE * scale_y;
        let y = group_index
            .map(|index| viewport.y + (index as f32 + 1.0) * line_height_px)
            .unwrap_or(viewport.y);
        let line_header_hex = line_header
            .as_ref()
            .and_then(|header| bytes.get(header.start..header.end))
            .map(hex_bytes)
            .unwrap_or_default();
        let line_header_raw_words = line_header
            .as_ref()
            .map(|header| header.raw_words)
            .unwrap_or([0; 12]);
        let fragment_count = fragments.len();
        let parent_text_unit_count = entry.text().encode_utf16().count();
        for (fragment_index, fragment) in fragments.iter().enumerate() {
            let fragment_grid_units = fragment.fragment_start_units.saturating_mul(2);
            let x = viewport.x
                + (f32::from(line_offset_units)
                    + leading_units.saturating_mul(2) as f32
                    + fragment_grid_units as f32)
                    * grid_unit_px;
            let fill = fallback_text_fill_color(document, &fragment.text);
            let fill_basis = shanai_lan_text_fill_basis(document, &fragment.text);
            let fragment_source_span = source_span
                .subspan_by_units(fragment.source_start_units, fragment.source_end_units);
            let previous_gap_units = (fragment_index > 0).then(|| {
                fragment
                    .source_start_units
                    .saturating_sub(fragments[fragment_index - 1].source_end_units)
            });
            let next_gap_units = (fragment_index + 1 < fragment_count).then(|| {
                fragments[fragment_index + 1]
                    .source_start_units
                    .saturating_sub(fragment.source_end_units)
            });
            let text_count_range_evidence =
                shanai_lan_text_count_range_evidence(document, &fragment_source_span);
            let style_link_evidence = shanai_lan_text_style_link_evidence(
                document,
                bytes,
                entry,
                fill_basis,
                &text_count_range_evidence,
            );
            slots.push(ShanaiLanTextSlot {
                text: fragment.text.clone(),
                x,
                y,
                font_size,
                fill,
                fill_basis,
                style_link_evidence,
                source_span: fragment_source_span,
                fragment_context: ShanaiLanTextRunFragmentContext {
                    parent_source_span: source_span.clone(),
                    parent_text_unit_count,
                    fragment_index,
                    fragment_count,
                    fragment_source_start_units: fragment.source_start_units,
                    fragment_source_end_units: fragment.source_end_units,
                    previous_gap_units,
                    next_gap_units,
                    style_boundary_proven: false,
                    promotion_blocked_reason: "document-text-fragment-style-boundary-unproven",
                },
                text_count_range_evidence,
                group_index,
                line_offset_units,
                leading_units,
                fragment_start_units: fragment.fragment_start_units,
                split_from_text_run: fragment.split_from_text_run,
                line_header_hex: line_header_hex.clone(),
                line_header_raw_words,
            });
        }
    }

    (!slots.is_empty()).then_some(ShanaiLanTextProjection {
        source: "/DocumentText",
        projection_kind: "documentTextGroupLineProjection",
        grid_unit_px,
        line_height_px,
        slots,
    })
}

fn shanai_lan_document_text_line_rule_projection(
    document: &Document,
    layout: PageLayout,
    page_number: usize,
) -> Option<ShanaiLanLineRuleProjection> {
    if page_number != 1 || !document_has_shanai_lan_fdm_command_evidence(document) {
        return None;
    }

    let bytes = document_text_raw_stream(document)?;
    let line_mark_intervals = shanai_lan_line_mark_intervals(document);
    let line_mark_profile = shanai_lan_line_mark_profile(document);
    shanai_lan_document_text_line_rule_projection_from_bytes(
        bytes,
        layout,
        &line_mark_intervals,
        line_mark_profile,
    )
}

fn shanai_lan_document_text_line_rule_projection_from_bytes(
    bytes: &[u8],
    layout: PageLayout,
    line_mark_intervals: &[ShanaiLanLineMarkInterval],
    line_mark_profile: &'static str,
) -> Option<ShanaiLanLineRuleProjection> {
    let map = map_document_text(bytes);
    let group_offsets = shanai_lan_text_group_offsets(bytes);
    let document_text_group_count = group_offsets.len();
    let document_text_line_header_count =
        shanai_lan_line_headers_in_groups(bytes, &group_offsets).len();
    let raw_max_extent_units = shanai_lan_text_max_extent_units(bytes).unwrap_or(0x0118);
    let max_extent_units = raw_max_extent_units
        .saturating_sub(SHANAI_LAN_TEXT_GRID_EXTENT_GUTTER_UNITS)
        .max(1);
    let viewport = fdm_projection_viewport(layout);
    let grid_unit_px = viewport.width / f32::from(max_extent_units);
    let scale_y = layout.height_px() / SHANAI_LAN_REFERENCE_PAGE_HEIGHT_PX;
    let line_height_px = 12.0 * SHANAI_LAN_TEXT_GROUP_LINE_HEIGHT_FACTOR * scale_y;
    let mut rules = Vec::new();
    let mut anchor_units = BTreeSet::new();
    let mut skipped_inline_line_header_count = 0usize;

    for entry in map
        .entries()
        .iter()
        .filter(|entry| entry.kind() == DocumentTextMapKind::SkippedInlineText)
    {
        let mut offset = entry.byte_start();
        while offset + 24 <= entry.byte_end().min(bytes.len()) {
            if let Some(header) = shanai_lan_line_header_at(bytes, offset)
                && header.end <= entry.byte_end()
                && header.extent_units > header.offset_units
                && header.extent_units.saturating_sub(header.offset_units)
                    >= SHANAI_LAN_LINE_RULE_MIN_SEGMENT_UNITS
                && let Some(group_index) =
                    shanai_lan_group_index_for_text_entry(&group_offsets, entry)
            {
                let x1 = viewport.x + f32::from(header.offset_units) * grid_unit_px;
                let x2 = viewport.x + f32::from(header.extent_units) * grid_unit_px;
                let y = viewport.y + (group_index as f32 + 1.0) * line_height_px;
                let line_header_hex = bytes
                    .get(header.start..header.end)
                    .map(hex_bytes)
                    .unwrap_or_default();
                let line_mark = shanai_lan_line_mark_for_header(line_mark_intervals, &header);
                anchor_units.insert(header.offset_units);
                anchor_units.insert(header.extent_units);
                skipped_inline_line_header_count += 1;
                rules.push(ShanaiLanLineRule {
                    x1,
                    y1: y,
                    x2,
                    y2: y,
                    orientation: "horizontal",
                    candidate_source: "skippedInlineLineHeader",
                    source_span: TextSourceSpan::new(
                        header.start,
                        header.end,
                        header.start / 2,
                        header.end / 2,
                    ),
                    group_index,
                    end_group_index: group_index,
                    line_offset_units: header.offset_units,
                    line_extent_units: header.extent_units,
                    line_header_hex,
                    line_header_raw_words: header.raw_words,
                    line_mark,
                });
                offset = header.end;
            } else {
                offset += 2;
            }
        }
    }
    append_shanai_lan_vertical_anchor_line_rules(
        bytes,
        &group_offsets,
        raw_max_extent_units,
        &anchor_units,
        viewport,
        grid_unit_px,
        line_height_px,
        &mut rules,
        line_mark_intervals,
    );

    (!rules.is_empty()).then_some(ShanaiLanLineRuleProjection {
        source: "/DocumentText",
        projection_kind: "documentTextLineRuleProjection",
        line_mark_profile,
        line_mark_interval_count: line_mark_intervals.len(),
        document_text_group_count,
        document_text_line_header_count,
        skipped_inline_line_header_count,
        grid_unit_px,
        line_height_px,
        stroke_width: SHANAI_LAN_LINE_RULE_STROKE_WIDTH_PX * scale_y,
        rules,
    })
}

fn shanai_lan_line_mark_intervals(document: &Document) -> Vec<ShanaiLanLineMarkInterval> {
    let Some(bytes) = document
        .raw_streams()
        .iter()
        .find(|stream| stream.name() == "/LineMark")
        .map(RawStream::bytes)
    else {
        return Vec::new();
    };
    shanai_lan_line_mark_intervals_from_bytes(bytes)
}

fn shanai_lan_line_mark_profile(document: &Document) -> &'static str {
    document
        .raw_streams()
        .iter()
        .find(|stream| stream.name() == "/LineMark")
        .map(RawStream::bytes)
        .map(shanai_lan_line_mark_profile_from_bytes)
        .unwrap_or(SHANAI_LAN_LINE_MARK_PROFILE_ABSENT)
}

fn shanai_lan_line_mark_profile_from_bytes(bytes: &[u8]) -> &'static str {
    if !shanai_lan_line_mark_intervals_from_bytes(bytes).is_empty() {
        return SHANAI_LAN_LINE_MARK_PROFILE_BE_DELTA_V1;
    }
    if utf16le_ascii_contains(bytes, "MacrosStreamStyle") {
        return SHANAI_LAN_LINE_MARK_PROFILE_MACRO_STYLE;
    }
    SHANAI_LAN_LINE_MARK_PROFILE_UNPARSED
}

fn line_mark_be_delta_record_byte_offset(record_index: usize) -> usize {
    LINE_MARK_BE_DELTA_HEADER_BYTES + record_index * LINE_MARK_BE_DELTA_RECORD_BYTES
}

fn line_mark_be_delta_record_word_index(record_index: usize) -> usize {
    line_mark_be_delta_record_byte_offset(record_index) / 2
}

fn shanai_lan_line_mark_intervals_from_bytes(bytes: &[u8]) -> Vec<ShanaiLanLineMarkInterval> {
    let Some(count) = read_be16_at(bytes, LINE_MARK_BE_DELTA_COUNT_OFFSET).map(usize::from) else {
        return Vec::new();
    };
    if count == 0
        || bytes.len()
            < LINE_MARK_BE_DELTA_HEADER_BYTES
                + count.saturating_mul(LINE_MARK_BE_DELTA_RECORD_BYTES)
    {
        return Vec::new();
    }

    let mut intervals = Vec::new();
    let mut unit_start = LINE_MARK_BE_DELTA_BASE_UNIT;
    for record_index in 0..count {
        let offset = line_mark_be_delta_record_byte_offset(record_index);
        let Some(delta_word) = read_be16_at(bytes, offset) else {
            break;
        };
        let Some(flag_word) = read_be16_at(bytes, offset + 2) else {
            break;
        };
        let delta = delta_word as i16;
        if delta <= 0 {
            break;
        }
        let unit_end = unit_start.saturating_add(delta as usize);
        intervals.push(ShanaiLanLineMarkInterval {
            record_index,
            unit_start,
            unit_end,
            flag_word,
        });
        unit_start = unit_end;
    }
    intervals
}

fn utf16le_ascii_contains(bytes: &[u8], needle: &str) -> bool {
    let mut encoded = Vec::with_capacity(needle.len() * 2);
    for unit in needle.encode_utf16() {
        encoded.extend_from_slice(&unit.to_le_bytes());
    }
    bytes.windows(encoded.len()).any(|window| window == encoded)
}

fn shanai_lan_line_mark_for_header(
    intervals: &[ShanaiLanLineMarkInterval],
    header: &ShanaiLanLineHeader,
) -> Option<ShanaiLanLineMarkInterval> {
    let unit = header.start / 2;
    intervals
        .iter()
        .copied()
        .find(|interval| interval.unit_start <= unit && unit < interval.unit_end)
}

#[allow(clippy::too_many_arguments)]
fn append_shanai_lan_vertical_anchor_line_rules(
    bytes: &[u8],
    group_offsets: &[usize],
    raw_max_extent_units: u16,
    anchor_units: &BTreeSet<u16>,
    viewport: FdmProjectionViewport,
    grid_unit_px: f32,
    line_height_px: f32,
    rules: &mut Vec<ShanaiLanLineRule>,
    line_mark_intervals: &[ShanaiLanLineMarkInterval],
) {
    let hidden_groups = rules
        .iter()
        .filter(|rule| rule.orientation == "horizontal")
        .map(|rule| rule.group_index)
        .collect::<BTreeSet<_>>();
    let Some(first_hidden_group) = hidden_groups.iter().next().copied() else {
        return;
    };
    let Some(last_hidden_group) = hidden_groups.iter().next_back().copied() else {
        return;
    };

    let min_group = first_hidden_group.saturating_sub(4);
    let max_group = last_hidden_group.saturating_add(1);
    let line_headers = shanai_lan_line_headers_in_groups(bytes, group_offsets);

    for anchor_unit in anchor_units {
        if *anchor_unit == 0 || *anchor_unit == raw_max_extent_units {
            continue;
        }

        let mut support_by_group = BTreeMap::new();
        for line_header in line_headers.iter().filter(|line_header| {
            (min_group..=max_group).contains(&line_header.group_index)
                && (line_header.header.offset_units == *anchor_unit
                    || line_header.header.extent_units == *anchor_unit)
        }) {
            support_by_group
                .entry(line_header.group_index)
                .or_insert(*line_header);
        }

        let mut run_start: Option<ShanaiLanLineHeaderInGroup> = None;
        let mut previous: Option<ShanaiLanLineHeaderInGroup> = None;
        for line_header in support_by_group.values().copied() {
            match previous {
                Some(previous_header)
                    if line_header.group_index == previous_header.group_index + 1 =>
                {
                    previous = Some(line_header);
                }
                Some(previous_header) => {
                    push_shanai_lan_vertical_anchor_line_rule(
                        bytes,
                        viewport,
                        grid_unit_px,
                        line_height_px,
                        *anchor_unit,
                        run_start.unwrap_or(previous_header),
                        previous_header,
                        rules,
                        line_mark_intervals,
                    );
                    run_start = Some(line_header);
                    previous = Some(line_header);
                }
                None => {
                    run_start = Some(line_header);
                    previous = Some(line_header);
                }
            }
        }
        if let (Some(run_start), Some(previous)) = (run_start, previous) {
            push_shanai_lan_vertical_anchor_line_rule(
                bytes,
                viewport,
                grid_unit_px,
                line_height_px,
                *anchor_unit,
                run_start,
                previous,
                rules,
                line_mark_intervals,
            );
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn push_shanai_lan_vertical_anchor_line_rule(
    bytes: &[u8],
    viewport: FdmProjectionViewport,
    grid_unit_px: f32,
    line_height_px: f32,
    anchor_unit: u16,
    run_start: ShanaiLanLineHeaderInGroup,
    run_end: ShanaiLanLineHeaderInGroup,
    rules: &mut Vec<ShanaiLanLineRule>,
    line_mark_intervals: &[ShanaiLanLineMarkInterval],
) {
    if run_end.group_index <= run_start.group_index {
        return;
    }
    let x = viewport.x + f32::from(anchor_unit) * grid_unit_px;
    let y1 = viewport.y + (run_start.group_index as f32 + 1.0) * line_height_px;
    let y2 = viewport.y + (run_end.group_index as f32 + 1.0) * line_height_px;
    let source_start = run_start.header.start.min(run_end.header.start);
    let source_end = run_start.header.end.max(run_end.header.end);
    let line_header_hex = bytes
        .get(run_start.header.start..run_start.header.end)
        .map(hex_bytes)
        .unwrap_or_default();
    let line_mark = shanai_lan_line_mark_for_header(line_mark_intervals, &run_start.header);
    rules.push(ShanaiLanLineRule {
        x1: x,
        y1,
        x2: x,
        y2,
        orientation: "vertical",
        candidate_source: "verticalAnchorRunFromLineHeaders",
        source_span: TextSourceSpan::new(
            source_start,
            source_end,
            source_start / 2,
            source_end / 2,
        ),
        group_index: run_start.group_index,
        end_group_index: run_end.group_index,
        line_offset_units: anchor_unit,
        line_extent_units: anchor_unit,
        line_header_hex,
        line_header_raw_words: run_start.header.raw_words,
        line_mark,
    });
}

fn shanai_lan_line_headers_in_groups(
    bytes: &[u8],
    group_offsets: &[usize],
) -> Vec<ShanaiLanLineHeaderInGroup> {
    let mut headers = Vec::new();
    let mut offset = 0usize;
    while offset + 24 <= bytes.len() {
        if let Some(header) = shanai_lan_line_header_at(bytes, offset) {
            if let Some(group_index) =
                shanai_lan_group_index_for_byte_offset(group_offsets, header.start)
            {
                headers.push(ShanaiLanLineHeaderInGroup {
                    group_index,
                    header,
                });
            }
            offset = header.end;
        } else {
            offset += 2;
        }
    }
    headers
}

fn document_text_raw_stream(document: &Document) -> Option<&[u8]> {
    raw_stream_bytes(document, DOCUMENT_TEXT_PATH)
}

fn raw_stream_bytes<'a>(document: &'a Document, name: &str) -> Option<&'a [u8]> {
    document
        .raw_streams()
        .iter()
        .find(|stream| stream.name() == name)
        .map(RawStream::bytes)
}

fn page_frame_projection(
    document: &Document,
    layout: PageLayout,
    page_number: usize,
) -> Option<PageFrameProjection> {
    if page_number != 1 {
        return None;
    }

    let mut shapes = Vec::new();
    for record in document.object_frame_records() {
        if let Some(shape) = page_frame_shape(record, layout) {
            shapes.push(shape);
        }
    }

    if shapes.is_empty() {
        return None;
    }

    Some(PageFrameProjection {
        source: "/Frame",
        projection_kind: "pageFrameProjection",
        page_assignment_decoded: false,
        record_count: document.object_frame_records().len(),
        shapes,
    })
}

fn page_frame_shape(
    record: &ObjectFrameRecordCandidate,
    layout: PageLayout,
) -> Option<PageFrameShape> {
    match record.object_type() {
        PAGE_FRAME_TITLE_OBJECT_TYPE => page_frame_title_shape(record, layout),
        PAGE_FRAME_PATTERN_BAR_OBJECT_TYPE => page_frame_pattern_bar_shape(record, layout, false),
        PAGE_FRAME_PATTERN_BAR_BOTTOM_OBJECT_TYPE => {
            page_frame_pattern_bar_shape(record, layout, true)
        }
        _ => None,
    }
}

fn page_frame_title_shape(
    record: &ObjectFrameRecordCandidate,
    layout: PageLayout,
) -> Option<PageFrameShape> {
    if record.width() == 0 || record.height() == 0 {
        return None;
    }

    let y = frame_record_unit_to_css_px(record.y());
    let width = frame_record_unit_to_css_px(record.width());
    let height = frame_record_unit_to_css_px(record.height());
    if !(48.0..=layout.width_px() * 0.75).contains(&width)
        || !(8.0..=layout.height_px() * 0.12).contains(&height)
    {
        return None;
    }
    if width / height.max(1.0) < PAGE_FRAME_MIN_TITLE_ASPECT_RATIO {
        return None;
    }

    let x = if record.x() == 0 {
        (layout.width_px() - width) / 2.0
    } else {
        frame_record_unit_to_css_px(record.x())
    };
    let corner_radius = frame_record_unit_to_css_px(record.corner_radius());

    Some(PageFrameShape {
        role: "titleRoundedFrame",
        row_index: record.row_index(),
        object_id: record.object_id(),
        object_type: record.object_type(),
        x,
        y,
        width,
        height,
        corner_radius,
        source_x: record.x(),
        source_y: record.y(),
        source_width: record.width(),
        source_height: record.height(),
        source_corner_radius: record.corner_radius(),
        source_style_id: record.style_id(),
        placement_basis: if record.x() == 0 {
            "centeredFrameRecordWidth"
        } else {
            "frameRecordFields"
        },
        style_basis: "frameRecordObjectTypeAndStyleId",
    })
}

fn page_frame_pattern_bar_shape(
    record: &ObjectFrameRecordCandidate,
    layout: PageLayout,
    bottom_origin: bool,
) -> Option<PageFrameShape> {
    if record.width() == 0 || record.height() == 0 {
        return None;
    }

    let x = frame_record_unit_to_css_px(record.x());
    let width = frame_record_unit_to_css_px(record.width());
    let height = frame_record_unit_to_css_px(record.height());
    let source_y = frame_record_unit_to_css_px(record.y());
    let y = if bottom_origin {
        layout.height_px() - source_y - height
    } else {
        source_y
    };
    if width < layout.width_px() * PAGE_FRAME_MIN_PATTERN_BAR_WIDTH_RATIO
        || y < PAGE_FRAME_MIN_PATTERN_BAR_Y_PX
        || height > PAGE_FRAME_MAX_PATTERN_BAR_HEIGHT_PX
    {
        return None;
    }

    Some(PageFrameShape {
        role: "horizontalPatternBar",
        row_index: record.row_index(),
        object_id: record.object_id(),
        object_type: record.object_type(),
        x,
        y,
        width,
        height,
        corner_radius: height * 0.45,
        source_x: record.x(),
        source_y: record.y(),
        source_width: record.width(),
        source_height: record.height(),
        source_corner_radius: record.corner_radius(),
        source_style_id: record.style_id(),
        placement_basis: if bottom_origin {
            "frameRecordBottomOriginFields"
        } else {
            "frameRecordFields"
        },
        style_basis: "frameRecordObjectTypeAndStyleId",
    })
}

fn frame_record_unit_to_css_px(value: u16) -> f32 {
    value as f32 * FRAME_RECORD_UNIT_TO_CSS_PX
}

fn page_mark_section_separator_projection(
    document: &Document,
    layout: PageLayout,
    page_number: usize,
) -> Option<PageMarkSeparatorProjection> {
    if page_number != 1 {
        return None;
    }

    let page_mark_bytes = raw_stream_bytes(document, PAGE_MARK_PATH)?;
    let text_projection = layout_box_text_projection(document, layout, page_number)?;
    let caption = text_projection
        .slots
        .iter()
        .rev()
        .find(|slot| slot.role == "caption")?;
    let body = text_projection
        .slots
        .iter()
        .find(|slot| slot.role == "body")?;
    let caption_bottom = caption.y + caption.line_height;
    let body_top = body.y;
    if body_top <= caption_bottom {
        return None;
    }

    let frame_projection = page_frame_projection(document, layout, page_number)?;
    let bar = frame_projection
        .shapes
        .iter()
        .filter(|shape| shape.role == "horizontalPatternBar")
        .max_by(|left, right| {
            left.width
                .partial_cmp(&right.width)
                .unwrap_or(Ordering::Equal)
        })?;

    let candidate = page_mark_separator_candidate(page_mark_bytes)?;
    let y = page_mark_centipoints_to_css_px(
        u32::from(candidate.y_centipoints) + u32::from(candidate.advance_centipoints),
    );
    if y < caption_bottom || y > body_top {
        return None;
    }

    Some(PageMarkSeparatorProjection {
        source: PAGE_MARK_PATH,
        projection_kind: "pageMarkSectionSeparatorProjection",
        role: "sectionSeparator",
        x: bar.x,
        y,
        width: bar.width,
        stroke_width: PAGE_MARK_SEPARATOR_STROKE_WIDTH_PX,
        source_record_offset: candidate.record_offset,
        source_record_index: candidate.record_index,
        source_line_start: candidate.line_start,
        source_line_end: candidate.line_end,
        source_y_centipoints: candidate.y_centipoints,
        source_advance_centipoints: candidate.advance_centipoints,
        placement_basis: "pageMarkCentipointInsideLayoutBoxCaptionBodyGap",
        style_basis: "pageMarkSeparatorTailAndRecurringMarkAdvance",
        page_assignment_decoded: false,
    })
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct PageMarkSeparatorCandidate {
    record_offset: usize,
    record_index: u32,
    line_start: u32,
    line_end: u32,
    y_centipoints: u16,
    advance_centipoints: u16,
}

fn page_mark_separator_candidate(bytes: &[u8]) -> Option<PageMarkSeparatorCandidate> {
    let advance_centipoints = page_mark_recurring_advance_centipoints(bytes).unwrap_or(0);
    let headers = page_mark_record_headers(bytes);
    for (header_index, header) in headers.iter().enumerate() {
        let next_offset = headers
            .get(header_index + 1)
            .map(|next| next.offset)
            .unwrap_or(bytes.len());
        let tail_start = header.offset.checked_add(16)?;
        if tail_start > next_offset || next_offset > bytes.len() {
            continue;
        }
        let tail = &bytes[tail_start..next_offset];
        let Some(y_centipoints) = page_mark_separator_tail_y_centipoints(tail) else {
            continue;
        };
        return Some(PageMarkSeparatorCandidate {
            record_offset: header.offset,
            record_index: header.index,
            line_start: header.line_start,
            line_end: header.line_end,
            y_centipoints,
            advance_centipoints,
        });
    }
    None
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct PageMarkRecordHeader {
    offset: usize,
    index: u32,
    flags: u32,
    line_start: u32,
    line_end: u32,
}

fn page_mark_record_headers(bytes: &[u8]) -> Vec<PageMarkRecordHeader> {
    let mut headers = Vec::new();
    let mut offset = 12usize;
    while offset + 16 <= bytes.len() {
        let Some(index) = read_be32_at(bytes, offset) else {
            break;
        };
        let Some(flags) = read_be32_at(bytes, offset + 4) else {
            break;
        };
        let Some(line_start) = read_be32_at(bytes, offset + 8) else {
            break;
        };
        let Some(line_end) = read_be32_at(bytes, offset + 12) else {
            break;
        };
        if flags == 0x0001_0000 && index < 256 && line_start <= line_end && line_end < 10_000 {
            headers.push(PageMarkRecordHeader {
                offset,
                index,
                flags,
                line_start,
                line_end,
            });
        }
        offset += 1;
    }
    headers
}

fn page_mark_separator_tail_y_centipoints(tail: &[u8]) -> Option<u16> {
    if !tail
        .windows(4)
        .any(|window| window == [0xff, 0xff, 0x00, 0x00])
    {
        return None;
    }
    tail.chunks_exact(2)
        .filter_map(|chunk| {
            let value = u16::from_be_bytes([chunk[0], chunk[1]]);
            (PAGE_MARK_SEPARATOR_MIN_Y_CENTIPOINTS..=PAGE_MARK_SEPARATOR_MAX_Y_CENTIPOINTS)
                .contains(&value)
                .then_some(value)
        })
        .next_back()
}

fn page_mark_recurring_advance_centipoints(bytes: &[u8]) -> Option<u16> {
    let mut candidates = Vec::new();
    for offset in 0..bytes.len().saturating_sub(3) {
        if bytes[offset] == 0x00 && bytes[offset + 1] == 0xff {
            let value = u16::from_be_bytes([bytes[offset + 2], bytes[offset + 3]]);
            if (1..=2_000).contains(&value) {
                candidates.push(value);
            }
        }
    }
    candidates.sort_unstable();
    let mut best = None;
    let mut best_count = 0usize;
    let mut index = 0usize;
    while index < candidates.len() {
        let value = candidates[index];
        let count = candidates[index..]
            .iter()
            .take_while(|candidate| **candidate == value)
            .count();
        if count > best_count {
            best = Some(value);
            best_count = count;
        }
        index += count;
    }
    best
}

fn page_mark_centipoints_to_css_px(value: u32) -> f32 {
    value as f32 * PAGE_MARK_CENTIPOINT_TO_CSS_PX
}

fn page_frame_text_placement(
    document: &Document,
    layout: PageLayout,
    page_number: usize,
    line_index: usize,
    line: &PageTextLine,
) -> Option<PageLayerTextPlacement> {
    let projection = page_frame_projection(document, layout, page_number)?;
    let title_frame = projection
        .shapes
        .iter()
        .find(|shape| shape.role == "titleRoundedFrame");
    let first_bar = projection
        .shapes
        .iter()
        .filter(|shape| shape.role == "horizontalPatternBar")
        .min_by(|left, right| left.y.partial_cmp(&right.y).unwrap_or(Ordering::Equal));

    if line_index == 0 && line.text().contains("制限時間") {
        let title_frame = title_frame?;
        let text_width = text_width_px(layout, line.text()) as f32;
        let x = ((layout.width_px() - text_width) / 2.0).max(layout.margin_px() * 0.5);
        let y = title_frame.y + title_frame.height + PAGE_FRAME_TIME_CAPTION_GAP_PX;
        return Some(PageLayerTextPlacement {
            x: x as f64,
            y: y as f64,
            baseline: (y + APP_FONT_SIZE_PX) as f64,
        });
    }

    if line_index == 0 {
        return None;
    }

    let first_bar = first_bar?;
    let body_x = layout_box_body_anchor_from_document(document, layout)
        .map(|(x, _, _)| x)
        .unwrap_or_else(|| layout.margin_px());
    let y = first_bar.y
        + first_bar.height
        + (APP_LINE_HEIGHT_PX * PAGE_FRAME_TEXT_AFTER_BAR_GAP_LINES)
        + (line_index.saturating_sub(1) as f32 * APP_LINE_HEIGHT_PX);

    Some(PageLayerTextPlacement {
        x: body_x as f64,
        y: y as f64,
        baseline: (y + APP_FONT_SIZE_PX) as f64,
    })
}

fn layout_box_body_anchor_from_document(
    document: &Document,
    layout: PageLayout,
) -> Option<(f32, f32, f32)> {
    let text_bytes = raw_stream_bytes(document, LAYOUT_BOX_TEXT_PATH)?;
    let layout_bytes = raw_stream_bytes(document, LAYOUT_BOX_PATH)?;
    let blocks = layout_box_text_blocks(text_bytes);
    let records = layout_box_record_candidates(layout_bytes);
    layout_box_body_anchor(&blocks, &records, layout)
}

fn layout_box_text_projection(
    document: &Document,
    layout: PageLayout,
    page_number: usize,
) -> Option<LayoutBoxTextProjection> {
    if page_number != 1 {
        return None;
    }

    let bytes = raw_stream_bytes(document, LAYOUT_BOX_TEXT_PATH)?;
    let blocks = layout_box_text_blocks(bytes);
    if blocks.is_empty() {
        return None;
    }
    let records = raw_stream_bytes(document, LAYOUT_BOX_PATH)
        .map(layout_box_record_candidates)
        .unwrap_or_default();
    let body_anchor = layout_box_body_anchor(&blocks, &records, layout);
    let title_frame_shape = document
        .object_frame_records()
        .iter()
        .find_map(|record| page_frame_title_shape(record, layout));
    let document_text = document_visible_text(document);
    let mut slots = Vec::new();

    for block in &blocks {
        for fragment in &block.fragments {
            let trimmed = fragment.text.trim();
            if trimmed.is_empty() || document_text.contains(trimmed) {
                continue;
            }
            let role = layout_box_text_role(block, &fragment.text);
            match role {
                "body" => {
                    let Some((record, x, y, width, origin_pt)) =
                        layout_box_record_text_box(block.index, &records, layout)
                    else {
                        continue;
                    };
                    let line_height =
                        LAYOUT_BOX_TEXT_BODY_FONT_SIZE_PX * LAYOUT_BOX_TEXT_LINE_HEIGHT_FACTOR;
                    for (line_index, line) in layout_box_wrapped_text_lines(
                        &fragment.text,
                        width,
                        LAYOUT_BOX_TEXT_BODY_FONT_SIZE_PX,
                    )
                    .into_iter()
                    .enumerate()
                    {
                        if line.trim().is_empty() {
                            continue;
                        }
                        slots.push(LayoutBoxTextSlot {
                            role,
                            text: line,
                            x,
                            y: y + line_index as f32 * line_height,
                            font_size: LAYOUT_BOX_TEXT_BODY_FONT_SIZE_PX,
                            line_height,
                            source_span: fragment.source_span.clone(),
                            block_index: block.index,
                            layout_record_index: Some(record.index),
                            layout_record_byte_range: Some((record.byte_start, record.byte_end)),
                            layout_x_pt: record.x_field,
                            layout_y_pt: record.y_field,
                            layout_width_pt: record.width_field,
                            inferred_origin_pt: Some(origin_pt),
                            placement_basis: "layoutBoxRecordFields",
                        });
                    }
                }
                "title" => {
                    let font_size = LAYOUT_BOX_TEXT_TITLE_FONT_SIZE_PX;
                    let text_width = text_width_px_for_font_size(font_size, trimmed) as f32;
                    let (x, y, placement_basis) = if let Some(frame) = &title_frame_shape {
                        (
                            frame.x + ((frame.width - text_width) / 2.0).max(0.0),
                            frame.y + ((frame.height - font_size) / 2.0).max(0.0),
                            "pageFrameTitleCenter",
                        )
                    } else {
                        (
                            ((layout.width_px() - text_width) / 2.0).max(layout.margin_px() * 0.5),
                            layout.margin_px() * 0.56,
                            "shortLeadingLayoutBoxText",
                        )
                    };
                    slots.push(LayoutBoxTextSlot {
                        role,
                        text: trimmed.to_string(),
                        x,
                        y,
                        font_size,
                        line_height: font_size * 1.2,
                        source_span: fragment.source_span.clone(),
                        block_index: block.index,
                        layout_record_index: records.get(block.index).map(|record| record.index),
                        layout_record_byte_range: records
                            .get(block.index)
                            .map(|record| (record.byte_start, record.byte_end)),
                        layout_x_pt: records.get(block.index).and_then(|record| record.x_field),
                        layout_y_pt: records.get(block.index).and_then(|record| record.y_field),
                        layout_width_pt: records
                            .get(block.index)
                            .and_then(|record| record.width_field),
                        inferred_origin_pt: records
                            .get(block.index)
                            .and_then(layout_box_record_origin_pt),
                        placement_basis,
                    });
                }
                "caption" => {
                    let font_size = LAYOUT_BOX_TEXT_CAPTION_FONT_SIZE_PX;
                    let text_width = text_width_px_for_font_size(font_size, trimmed) as f32;
                    let body_line_height =
                        LAYOUT_BOX_TEXT_BODY_FONT_SIZE_PX * LAYOUT_BOX_TEXT_LINE_HEIGHT_FACTOR;
                    let y = body_anchor
                        .map(|(_, body_y, _)| body_y - body_line_height * 2.0)
                        .unwrap_or(layout.height_px() * 0.38);
                    slots.push(LayoutBoxTextSlot {
                        role,
                        text: trimmed.to_string(),
                        x: ((layout.width_px() - text_width) / 2.0).max(layout.margin_px() * 0.5),
                        y,
                        font_size,
                        line_height: font_size * 1.25,
                        source_span: fragment.source_span.clone(),
                        block_index: block.index,
                        layout_record_index: records.get(block.index).map(|record| record.index),
                        layout_record_byte_range: records
                            .get(block.index)
                            .map(|record| (record.byte_start, record.byte_end)),
                        layout_x_pt: records.get(block.index).and_then(|record| record.x_field),
                        layout_y_pt: records.get(block.index).and_then(|record| record.y_field),
                        layout_width_pt: records
                            .get(block.index)
                            .and_then(|record| record.width_field),
                        inferred_origin_pt: records
                            .get(block.index)
                            .and_then(layout_box_record_origin_pt),
                        placement_basis: "relativeToLayoutBoxBodyAnchor",
                    });
                }
                _ => {}
            }
        }
    }

    (!slots.is_empty()).then_some(LayoutBoxTextProjection {
        source: LAYOUT_BOX_TEXT_PATH,
        projection_kind: "layoutBoxTextProjection",
        block_count: blocks.len(),
        layout_record_count: records.len(),
        position_table_present: raw_stream_bytes(document, LAYOUT_BOX_TEXT_POSITION_TABLES_PATH)
            .is_some(),
        page_assignment_decoded: false,
        slots,
    })
}

fn layout_box_text_blocks(bytes: &[u8]) -> Vec<LayoutBoxTextBlock> {
    let mut blocks = Vec::new();
    let mut offset = 0usize;
    while let Some(relative) = bytes[offset..]
        .windows(LAYOUT_BOX_TEXT_MAGIC.len())
        .position(|window| window == LAYOUT_BOX_TEXT_MAGIC)
    {
        let byte_start = offset + relative;
        let Some(declared_unit_count) =
            read_be32_at(bytes, byte_start + LAYOUT_BOX_TEXT_MAGIC.len())
                .and_then(|value| usize::try_from(value).ok())
        else {
            break;
        };
        let payload_start = byte_start + LAYOUT_BOX_TEXT_MAGIC.len() + 4;
        let declared_payload_end =
            payload_start.saturating_add(declared_unit_count.saturating_mul(2));
        let next_magic = bytes
            .get(payload_start..)
            .and_then(|tail| {
                tail.windows(LAYOUT_BOX_TEXT_MAGIC.len())
                    .position(|window| window == LAYOUT_BOX_TEXT_MAGIC)
            })
            .map(|relative| payload_start + relative);
        let payload_end = declared_payload_end
            .min(next_magic.unwrap_or(bytes.len()))
            .min(bytes.len());
        if payload_start > payload_end {
            break;
        }
        let fragments = layout_box_text_fragments(bytes, payload_start, payload_end);
        blocks.push(LayoutBoxTextBlock {
            index: blocks.len(),
            byte_start,
            byte_end: payload_end,
            payload_start,
            payload_end,
            declared_unit_count,
            fragments,
        });
        offset = payload_end.max(byte_start + 1);
    }
    blocks
}

fn layout_box_text_fragments(
    source_bytes: &[u8],
    payload_start: usize,
    payload_end: usize,
) -> Vec<LayoutBoxTextFragment> {
    let Some(payload) = source_bytes.get(payload_start..payload_end) else {
        return Vec::new();
    };
    let mut fragments = map_document_text(payload)
        .entries()
        .iter()
        .filter(|entry| {
            matches!(
                entry.kind(),
                DocumentTextMapKind::TextRun
                    | DocumentTextMapKind::InlineText
                    | DocumentTextMapKind::SkippedInlineText
            ) && !entry.text().trim().is_empty()
        })
        .map(|entry| {
            let byte_start = payload_start + entry.byte_start();
            let byte_end = payload_start + entry.byte_end();
            LayoutBoxTextFragment {
                text: entry.text().trim_end().to_string(),
                source_span: TextSourceSpan::new(
                    byte_start,
                    byte_end,
                    byte_start / 2,
                    byte_end / 2,
                ),
            }
        })
        .collect::<Vec<_>>();
    if !fragments.is_empty() {
        return fragments;
    }

    if let Some((text, byte_start, byte_end)) =
        decode_plain_layout_box_text_payload(payload, payload_start)
    {
        fragments.push(LayoutBoxTextFragment {
            text,
            source_span: TextSourceSpan::new(byte_start, byte_end, byte_start / 2, byte_end / 2),
        });
    }
    fragments
}

fn decode_plain_layout_box_text_payload(
    payload: &[u8],
    payload_start: usize,
) -> Option<(String, usize, usize)> {
    let mut text = String::new();
    let mut first_text_unit = None;
    let mut last_text_unit = None;
    for (unit_index, chunk) in payload.chunks_exact(2).enumerate() {
        let code = u16::from_be_bytes([chunk[0], chunk[1]]);
        let character = match code {
            0x0009 => '\t',
            0x000a | 0x000d => '\n',
            0x0020..=0xd7ff | 0xe000..=0xfffd if code != 0xffff => char::from_u32(u32::from(code))?,
            _ => continue,
        };
        if !matches!(character, '\0') {
            first_text_unit.get_or_insert(unit_index);
            last_text_unit = Some(unit_index + 1);
            text.push(character);
        }
    }
    let text = text
        .trim_end_matches([' ', '\u{3000}', '\n', '\r', '\t'])
        .to_string();
    if text.trim().is_empty() {
        return None;
    }
    let byte_start = payload_start + first_text_unit.unwrap_or_default() * 2;
    let byte_end = payload_start + last_text_unit.unwrap_or_default() * 2;
    Some((text, byte_start, byte_end))
}

fn layout_box_record_candidates(bytes: &[u8]) -> Vec<LayoutBoxRecordCandidate> {
    let starts = find_layout_box_record_starts(bytes);
    starts
        .iter()
        .enumerate()
        .map(|(index, byte_start)| {
            let byte_end = starts.get(index + 1).copied().unwrap_or(bytes.len());
            let record = &bytes[*byte_start..byte_end];
            LayoutBoxRecordCandidate {
                index,
                byte_start: *byte_start,
                byte_end,
                origin_field: read_be16_at(record, LAYOUT_BOX_RECORD_ORIGIN_FIELD_OFFSET),
                x_field: read_be16_at(record, LAYOUT_BOX_RECORD_X_FIELD_OFFSET),
                y_field: read_be16_at(record, LAYOUT_BOX_RECORD_Y_FIELD_OFFSET),
                width_field: read_be16_at(record, LAYOUT_BOX_RECORD_WIDTH_FIELD_OFFSET),
            }
        })
        .collect()
}

fn find_layout_box_record_starts(bytes: &[u8]) -> Vec<usize> {
    bytes
        .windows(LAYOUT_BOX_RECORD_PREFIX.len())
        .enumerate()
        .filter_map(|(offset, window)| (window == LAYOUT_BOX_RECORD_PREFIX).then_some(offset))
        .collect()
}

fn layout_box_text_role(block: &LayoutBoxTextBlock, text: &str) -> &'static str {
    let trimmed = text.trim();
    if trimmed.chars().count() >= LAYOUT_BOX_TEXT_BODY_MIN_CHARS {
        return "body";
    }
    if block.index == 0 && trimmed.chars().count() <= 32 && !trimmed.contains('\n') {
        return "title";
    }
    if trimmed.contains("より") || trimmed.contains("抜粋") || trimmed.contains('\'') {
        return "caption";
    }
    "label"
}

fn layout_box_body_anchor(
    blocks: &[LayoutBoxTextBlock],
    records: &[LayoutBoxRecordCandidate],
    layout: PageLayout,
) -> Option<(f32, f32, f32)> {
    blocks.iter().find_map(|block| {
        block
            .fragments
            .iter()
            .any(|fragment| layout_box_text_role(block, &fragment.text) == "body")
            .then(|| layout_box_record_text_box(block.index, records, layout))
            .flatten()
            .map(|(_, x, y, width, _)| (x, y, width))
    })
}

fn layout_box_record_text_box(
    block_index: usize,
    records: &[LayoutBoxRecordCandidate],
    _layout: PageLayout,
) -> Option<(&LayoutBoxRecordCandidate, f32, f32, f32, f32)> {
    let record = records.get(block_index)?;
    let x = record.x_field?;
    let y = record.y_field?;
    let width = record.width_field?;
    if !(LAYOUT_BOX_TEXT_MIN_RENDER_WIDTH_PT..=LAYOUT_BOX_TEXT_MAX_RENDER_WIDTH_PT).contains(&width)
        || x > LAYOUT_BOX_TEXT_MAX_RENDER_WIDTH_PT
        || y > 1200
    {
        return None;
    }
    let origin_pt = layout_box_record_origin_pt(record).unwrap_or(0.0);
    Some((
        record,
        (f32::from(x) + origin_pt) * PDF_POINT_TO_CSS_PX,
        (f32::from(y) + origin_pt) * PDF_POINT_TO_CSS_PX,
        f32::from(width) * PDF_POINT_TO_CSS_PX,
        origin_pt,
    ))
}

fn layout_box_record_origin_pt(record: &LayoutBoxRecordCandidate) -> Option<f32> {
    record
        .origin_field
        .map(|value| f32::from(value) * (2.0 / 3.0))
}

fn layout_box_wrapped_text_lines(text: &str, width_px: f32, font_size: f32) -> Vec<String> {
    let max_columns = ((width_px / (font_size * 0.55)).floor() as usize).max(8);
    let mut lines = Vec::new();
    for paragraph in text.split('\n') {
        let mut current = String::new();
        let mut width = 0usize;
        for character in paragraph.trim_end().chars() {
            let char_width = display_column_width(character);
            if width > 0 && width + char_width > max_columns {
                lines.push(std::mem::take(&mut current));
                width = 0;
            }
            current.push(character);
            width += char_width;
        }
        if !current.trim().is_empty() {
            lines.push(current);
        }
    }
    lines
}

fn document_visible_text(document: &Document) -> String {
    document_paragraph_texts(document)
        .into_iter()
        .map(|(_, text)| text)
        .collect::<Vec<_>>()
        .join("\n")
}

fn shanai_lan_text_group_offsets(bytes: &[u8]) -> Vec<usize> {
    let mut offsets = Vec::new();
    let mut offset = 0usize;
    while offset + 4 <= bytes.len() {
        if bytes[offset..].starts_with(&[0x00, 0x1c, 0x00, 0x10]) {
            offsets.push(offset);
        }
        offset += 2;
    }
    offsets
}

fn shanai_lan_text_max_extent_units(bytes: &[u8]) -> Option<u16> {
    let mut max_extent: Option<u16> = None;
    let mut offset = 0usize;
    while offset + 24 <= bytes.len() {
        if let Some(header) = shanai_lan_line_header_at(bytes, offset) {
            max_extent = Some(max_extent.unwrap_or(0).max(header.extent_units));
            offset = header.end;
        } else {
            offset += 2;
        }
    }
    max_extent
}

fn shanai_lan_group_index_for_text_entry(
    group_offsets: &[usize],
    entry: &DocumentTextMapEntry,
) -> Option<usize> {
    shanai_lan_group_index_for_byte_offset(group_offsets, entry.byte_start())
}

fn shanai_lan_group_index_for_byte_offset(
    group_offsets: &[usize],
    byte_offset: usize,
) -> Option<usize> {
    group_offsets
        .iter()
        .rposition(|offset| *offset < byte_offset)
}

fn shanai_lan_line_header_for_text_entry(
    bytes: &[u8],
    entry: &DocumentTextMapEntry,
) -> Option<ShanaiLanLineHeader> {
    let search_start = entry.byte_start().saturating_sub(64);
    let mut offset = entry.byte_start().saturating_sub(2);
    while offset >= search_start && offset + 24 <= bytes.len() {
        if let Some(header) = shanai_lan_line_header_at(bytes, offset)
            && header.end <= entry.byte_start()
        {
            return Some(header);
        }
        if offset < 2 {
            break;
        }
        offset -= 2;
    }
    None
}

fn shanai_lan_line_header_at(bytes: &[u8], offset: usize) -> Option<ShanaiLanLineHeader> {
    if offset + 24 > bytes.len() || !bytes[offset..].starts_with(&[0x00, 0x1c, 0x00, 0x30]) {
        return None;
    }
    let mut words = [0u16; 12];
    for (index, chunk) in bytes[offset..offset + 24].chunks_exact(2).enumerate() {
        words[index] = u16::from_be_bytes([chunk[0], chunk[1]]);
    }
    if words[2] == 0
        || words[6] != 0x00ff
        || words[7] != 0
        || words[9] != 0
        || words[10] != 0x0030
        || words[11] != 0x001f
    {
        return None;
    }
    Some(ShanaiLanLineHeader {
        offset_units: words[4],
        extent_units: words[5],
        font_size_units: words[2],
        raw_words: words,
        start: offset,
        end: offset + 24,
    })
}

fn shanai_lan_visible_text_fragments(text: &str) -> Vec<ShanaiLanTextFragment> {
    let characters = text.chars().collect::<Vec<_>>();
    let mut visible_start = 0usize;
    while visible_start < characters.len()
        && matches!(
            characters[visible_start],
            ' ' | '\u{3000}' | '\n' | '\r' | '\t'
        )
    {
        visible_start += 1;
    }

    let mut visible_end = characters.len();
    while visible_end > visible_start
        && matches!(
            characters[visible_end - 1],
            ' ' | '\u{3000}' | '\n' | '\r' | '\t'
        )
    {
        visible_end -= 1;
    }

    if visible_start >= visible_end {
        return Vec::new();
    }

    let visible_text = characters[visible_start..visible_end]
        .iter()
        .collect::<String>();
    if visible_text.trim_matches(|character| matches!(character, ' ' | '\u{3000}')) == "#" {
        return Vec::new();
    }

    let mut ranges = Vec::new();
    let mut fragment_start = visible_start;
    let mut offset = visible_start;
    while offset < visible_end {
        if matches!(characters[offset], ' ' | '\u{3000}') {
            let gap_start = offset;
            let mut gap_end = offset;
            while gap_end < visible_end && matches!(characters[gap_end], ' ' | '\u{3000}') {
                gap_end += 1;
            }
            let gap_units = shanai_lan_spacing_units_for_chars(&characters[gap_start..gap_end]);
            if gap_units >= SHANAI_LAN_TEXT_FRAGMENT_GAP_UNITS
                && fragment_start < gap_start
                && gap_end < visible_end
            {
                ranges.push((fragment_start, gap_start));
                fragment_start = gap_end;
            }
            offset = gap_end;
        } else {
            offset += 1;
        }
    }
    if fragment_start < visible_end {
        ranges.push((fragment_start, visible_end));
    }

    let split_from_text_run = ranges.len() > 1;
    ranges
        .into_iter()
        .filter_map(|(start, end)| {
            let fragment_text = characters[start..end].iter().collect::<String>();
            let trimmed =
                fragment_text.trim_matches(|character| matches!(character, ' ' | '\u{3000}'));
            if trimmed.is_empty() || trimmed == "#" {
                return None;
            }
            Some(ShanaiLanTextFragment {
                text: trimmed.to_string(),
                source_start_units: utf16_units_for_chars(&characters[..start]),
                source_end_units: utf16_units_for_chars(&characters[..end]),
                fragment_start_units: shanai_lan_spacing_units_for_chars(
                    &characters[visible_start..start],
                ),
                split_from_text_run,
            })
        })
        .collect()
}

fn shanai_lan_spacing_units_for_chars(characters: &[char]) -> usize {
    characters
        .iter()
        .map(|character| match character {
            '\u{3000}' => 2,
            '\t' => APP_TAB_COLUMNS,
            _ => character.len_utf16(),
        })
        .sum()
}

fn utf16_units_for_chars(characters: &[char]) -> usize {
    characters
        .iter()
        .map(|character| character.len_utf16())
        .sum()
}

fn leading_display_units(text: &str) -> usize {
    text.chars()
        .take_while(|character| matches!(character, ' ' | '\u{3000}'))
        .map(display_column_width)
        .sum()
}

fn push_shanai_lan_text_projection_svg(
    svg: &mut String,
    projection: &ShanaiLanTextProjection,
    font_family: &str,
) {
    svg.push_str(&format!(
        "<g class=\"rjtd-shanai-lan-text-projection\" data-source=\"{}\" data-projection-kind=\"{}\" data-decoded=\"false\" data-placement-proven=\"false\" data-grid-unit-px=\"{:.3}\" data-line-height-px=\"{:.3}\" data-baseline-factor=\"{:.3}\">",
        escape_xml(projection.source),
        escape_xml(projection.projection_kind),
        projection.grid_unit_px,
        projection.line_height_px,
        SHANAI_LAN_TEXT_BASELINE_FACTOR
    ));
    let font_family = escape_xml(font_family);
    for slot in &projection.slots {
        let group_index = slot
            .group_index
            .map(|index| index.to_string())
            .unwrap_or_else(|| "-".to_string());
        let text_count_range_indexes =
            shanai_lan_text_count_range_indexes_attr(&slot.text_count_range_evidence);
        let text_count_range_bases =
            shanai_lan_text_count_range_bases_attr(&slot.text_count_range_evidence);
        let line_header_raw_words_hex =
            shanai_lan_line_header_raw_words_hex_attr(&slot.line_header_raw_words);
        let document_view_style_group_candidate = slot
            .style_link_evidence
            .document_view_style_group_candidate
            .map(|group_id| group_id.to_string())
            .unwrap_or_else(|| "-".to_string());
        let document_view_style_group_candidate_basis = slot
            .style_link_evidence
            .document_view_style_group_candidate_basis
            .unwrap_or("-");
        let fill_color_promotion_blocked_reason = slot
            .style_link_evidence
            .fill_color_promotion_blocked_reason
            .unwrap_or("-");
        let group_header_candidate = slot
            .style_link_evidence
            .document_text_group_header_candidate
            .as_ref();
        let group_header_candidate_present = group_header_candidate.is_some();
        let group_header_candidate_raw_words_hex = group_header_candidate
            .map(|candidate| shanai_lan_u16_words_hex_attr(&candidate.raw_words))
            .unwrap_or_default();
        let group_header_candidate_blocked_reason = group_header_candidate
            .map(|candidate| candidate.promotion_blocked_reason)
            .unwrap_or("-");
        let inline_style_candidate = slot
            .style_link_evidence
            .document_text_inline_style_candidate
            .as_ref();
        let inline_style_candidate_present = inline_style_candidate.is_some();
        let inline_style_candidate_selector = inline_style_candidate
            .and_then(|candidate| candidate.selector)
            .map(|selector| format!("0x{selector:04x}"))
            .unwrap_or_else(|| "-".to_string());
        let inline_style_candidate_raw_words_hex = inline_style_candidate
            .map(|candidate| shanai_lan_u16_words_hex_attr(&candidate.raw_words))
            .unwrap_or_default();
        let inline_style_candidate_blocked_reason = inline_style_candidate
            .map(|candidate| candidate.promotion_blocked_reason)
            .unwrap_or("-");
        let parent_text_run_byte_range = format!(
            "{}..{}",
            slot.fragment_context.parent_source_span.byte_start(),
            slot.fragment_context.parent_source_span.byte_end()
        );
        let parent_text_run_unit_range = format!(
            "{}..{}",
            slot.fragment_context.parent_source_span.unit_start(),
            slot.fragment_context.parent_source_span.unit_end()
        );
        let fragment_source_unit_range = format!(
            "{}..{}",
            slot.fragment_context.fragment_source_start_units,
            slot.fragment_context.fragment_source_end_units
        );
        let previous_gap_units = slot
            .fragment_context
            .previous_gap_units
            .map(|value| value.to_string())
            .unwrap_or_else(|| "-".to_string());
        let next_gap_units = slot
            .fragment_context
            .next_gap_units
            .map(|value| value.to_string())
            .unwrap_or_else(|| "-".to_string());
        svg.push_str(&format!(
            "<text class=\"rjtd-text rjtd-shanai-lan-text\" data-source=\"{}\" data-projection-kind=\"{}\" data-group-index=\"{}\" data-line-offset-units=\"{}\" data-leading-units=\"{}\" data-fragment-start-units=\"{}\" data-split-from-text-run=\"{}\" data-parent-text-run-byte-range=\"{}\" data-parent-text-run-unit-range=\"{}\" data-parent-text-run-unit-count=\"{}\" data-fragment-index=\"{}\" data-fragment-count=\"{}\" data-fragment-source-unit-range=\"{}\" data-previous-gap-units=\"{}\" data-next-gap-units=\"{}\" data-fragment-style-boundary-proven=\"{}\" data-fragment-style-blocked-reason=\"{}\" data-line-header-hex=\"{}\" data-line-header-raw-words-hex=\"{}\" data-fill-color-basis=\"{}\" data-style-link-proven=\"{}\" data-style-link-blocked-reason=\"{}\" data-text-layout-style-record-count=\"{}\" data-document-view-style-group-count=\"{}\" data-document-view-style-group-candidate=\"{}\" data-document-view-style-group-candidate-basis=\"{}\" data-document-text-group-header-candidate=\"{}\" data-document-text-group-header-raw-words-hex=\"{}\" data-document-text-group-header-blocked-reason=\"{}\" data-document-text-inline-style-candidate=\"{}\" data-document-text-inline-style-selector=\"{}\" data-document-text-inline-style-raw-words-hex=\"{}\" data-document-text-inline-style-blocked-reason=\"{}\" data-fill-color-promotion-blocked-reason=\"{}\" data-text-count-range-evidence-count=\"{}\" data-text-count-range-indexes=\"{}\" data-text-count-range-bases=\"{}\" x=\"{:.1}\" y=\"{:.1}\" font-family=\"{}\" font-size=\"{:.1}\" fill=\"{}\" letter-spacing=\"0\" xml:space=\"preserve\">{}</text>",
            escape_xml(projection.source),
            escape_xml(projection.projection_kind),
            escape_xml(&group_index),
            slot.line_offset_units,
            slot.leading_units,
            slot.fragment_start_units,
            slot.split_from_text_run,
            escape_xml(&parent_text_run_byte_range),
            escape_xml(&parent_text_run_unit_range),
            slot.fragment_context.parent_text_unit_count,
            slot.fragment_context.fragment_index,
            slot.fragment_context.fragment_count,
            escape_xml(&fragment_source_unit_range),
            escape_xml(&previous_gap_units),
            escape_xml(&next_gap_units),
            slot.fragment_context.style_boundary_proven,
            escape_xml(slot.fragment_context.promotion_blocked_reason),
            escape_xml(&slot.line_header_hex),
            escape_xml(&line_header_raw_words_hex),
            escape_xml(slot.fill_basis),
            slot.style_link_evidence.style_link_proven,
            escape_xml(
                slot.style_link_evidence
                    .style_link_promotion_blocked_reason
            ),
            slot.style_link_evidence.text_layout_style_record_count,
            slot.style_link_evidence.document_view_style_group_count,
            escape_xml(&document_view_style_group_candidate),
            escape_xml(document_view_style_group_candidate_basis),
            group_header_candidate_present,
            escape_xml(&group_header_candidate_raw_words_hex),
            escape_xml(group_header_candidate_blocked_reason),
            inline_style_candidate_present,
            escape_xml(&inline_style_candidate_selector),
            escape_xml(&inline_style_candidate_raw_words_hex),
            escape_xml(inline_style_candidate_blocked_reason),
            escape_xml(fill_color_promotion_blocked_reason),
            slot.text_count_range_evidence.len(),
            escape_xml(&text_count_range_indexes),
            escape_xml(&text_count_range_bases),
            slot.x,
            shanai_lan_text_baseline_y(slot),
            font_family,
            slot.font_size,
            slot.fill,
            escape_xml(&svg_visual_text(&slot.text))
        ));
    }
    svg.push_str("</g>");
}

fn shanai_lan_text_count_range_indexes_attr(
    evidence: &[ShanaiLanTextCountRangeEvidence],
) -> String {
    evidence
        .iter()
        .map(|item| item.index.to_string())
        .collect::<Vec<_>>()
        .join(",")
}

fn shanai_lan_text_count_range_bases_attr(evidence: &[ShanaiLanTextCountRangeEvidence]) -> String {
    evidence
        .iter()
        .map(|item| item.basis.as_str())
        .collect::<Vec<_>>()
        .join(",")
}

fn shanai_lan_line_header_raw_words_hex_attr(words: &[u16; 12]) -> String {
    shanai_lan_u16_words_hex_attr(words)
}

fn shanai_lan_u16_words_hex_attr(words: &[u16]) -> String {
    words
        .iter()
        .map(|word| format!("0x{word:04x}"))
        .collect::<Vec<_>>()
        .join(",")
}

fn shanai_lan_text_baseline_y(slot: &ShanaiLanTextSlot) -> f32 {
    slot.y + slot.font_size * SHANAI_LAN_TEXT_BASELINE_FACTOR
}

fn render_text_page_svg(
    lines: &[PageTextLine],
    page_number: usize,
    _page_count: usize,
    layout: PageLayout,
    writing_mode: WritingMode,
    document: &Document,
    decoration: Option<&PageDecoration>,
) -> String {
    let mut svg = String::new();
    svg.push_str(&format!(
        "<svg xmlns=\"http://www.w3.org/2000/svg\" xmlns:xlink=\"http://www.w3.org/1999/xlink\" width=\"{:.1}\" height=\"{:.1}\" viewBox=\"0 0 {:.1} {:.1}\">",
        layout.width_px(),
        layout.height_px(),
        layout.width_px(),
        layout.height_px()
    ));
    svg.push_str("<rect width=\"100%\" height=\"100%\" fill=\"#ffffff\"/>");
    let font_family = document_font_family_css(document);
    push_page_frame_projection_svg(&mut svg, layout, document, page_number);
    push_page_mark_section_separator_svg(&mut svg, layout, document, page_number);
    push_visual_list_diagnostic_svg(&mut svg, layout, document, page_number);
    push_embedding_frame_diagnostic_svg(&mut svg, layout, document, lines, page_number);
    push_success_data_test_title_art_projection_svg(&mut svg, layout, document, lines, page_number);
    push_success_data_test_answer_sheet_projection_svg(
        &mut svg,
        layout,
        document,
        page_number,
        &font_family,
    );
    push_jseq_formula_projection_svg(&mut svg, layout, document, lines, page_number, &font_family);
    // Line-rule candidates stay in the layer tree until the topology decoder is reliable enough
    // to render them without adding false connector trunks.
    let fdm_vector_primitives_rendered =
        push_fdm_vector_primitive_svg(&mut svg, layout, document, page_number);

    if let Some(projection) = shanai_lan_document_text_projection(document, layout, page_number) {
        push_shanai_lan_text_projection_svg(&mut svg, &projection, &font_family);
    } else if let Some(projection) = observed_form_text_projection(document, layout, page_number) {
        push_observed_form_text_projection_svg(&mut svg, &projection, &font_family);
    } else if writing_mode.is_vertical() {
        let placement = vertical_page_text_placement(layout, lines);
        svg.push_str("<g writing-mode=\"vertical-rl\" glyph-orientation-vertical=\"auto\">");
        for (index, line) in lines.iter().enumerate() {
            if line.text().is_empty() {
                continue;
            }

            let mut x =
                layout.width_px() - layout.margin_px() - (index as f32 * APP_LINE_HEIGHT_PX)
                    + placement.x_shift_px;
            let mut y = placement.y_start_px;
            if is_centered_ginga_title_page(page_number, line) {
                let line_extent = vertical_text_advance_px(line.text()) as f32;
                x = layout.width_px() / 2.0;
                y = ((layout.height_px() - line_extent) / 2.0).max(layout.margin_px());
            }

            for fragment in page_text_line_fragments(document, line) {
                if fragment.text.is_empty() {
                    continue;
                }
                let fill_color = fallback_text_fill_color(document, &fragment.text);

                push_svg_text_run(
                    &mut svg,
                    "rjtd-text",
                    x,
                    y,
                    &font_family,
                    APP_FONT_SIZE_PX,
                    fill_color,
                    &fragment.text,
                    Some("vertical-rl"),
                );
                if let Some(annotation) = &fragment.ruby_annotation {
                    push_svg_ruby_annotation(
                        &mut svg,
                        x + (APP_FONT_SIZE_PX * 0.72),
                        y,
                        &font_family,
                        annotation,
                        true,
                    );
                }
                y += vertical_text_advance_px(&fragment.text) as f32;
            }
        }
        svg.push_str("</g>");
    } else {
        if let Some(slots) = success_data_test_top_text_projection(document, page_number) {
            push_success_data_test_top_text_projection_svg(
                &mut svg,
                document,
                layout,
                slots,
                &font_family,
            );
        }
        let text_origin = fallback_text_origin(layout, document);
        let mut fallback_visual_line_index = 0usize;
        for (index, line) in lines.iter().enumerate() {
            if line.text().is_empty() {
                continue;
            }
            if success_data_test_top_text_line_should_skip(document, page_number, line) {
                continue;
            }
            let frame_text_placement = page_frame_text_placement(
                document,
                layout,
                page_number,
                fallback_visual_line_index,
                line,
            );
            let mut x = frame_text_placement
                .map(|placement| placement.x as f32)
                .or_else(|| text_origin.map(|origin| origin.0))
                .unwrap_or_else(|| layout.margin_px());
            let y = frame_text_placement
                .map(|placement| placement.baseline as f32)
                .unwrap_or_else(|| {
                    text_origin
                        .map(|origin| origin.1)
                        .unwrap_or_else(|| layout.margin_px())
                        + APP_FONT_SIZE_PX
                        + (index as f32 * APP_LINE_HEIGHT_PX)
                });
            for fragment in page_text_line_fragments(document, line) {
                if fragment.text.is_empty() {
                    continue;
                }
                if fragment_overlaps_rendered_table_projection(
                    layout,
                    document,
                    lines,
                    page_number,
                    &fragment,
                ) {
                    continue;
                }
                let width = text_width_px(layout, &fragment.text) as f32;
                let fill_color = fallback_text_fill_color(document, &fragment.text);
                push_svg_text_run(
                    &mut svg,
                    "rjtd-text",
                    x,
                    y,
                    &font_family,
                    APP_FONT_SIZE_PX,
                    fill_color,
                    &fragment.text,
                    None,
                );
                if let Some(annotation) = &fragment.ruby_annotation {
                    push_svg_ruby_annotation(
                        &mut svg,
                        x + (width / 2.0),
                        y - (APP_FONT_SIZE_PX * 0.75),
                        &font_family,
                        annotation,
                        false,
                    );
                }
                x += width;
            }
            fallback_visual_line_index += 1;
        }
    }
    if let Some(projection) = layout_box_text_projection(document, layout, page_number) {
        push_layout_box_text_projection_svg(&mut svg, &projection, &font_family);
    }
    if let Some(decoration) = decoration {
        push_page_decoration_svg(&mut svg, layout, writing_mode, decoration, &font_family);
    }
    push_success_data_test_cone_diagram_projection_svg(
        &mut svg,
        layout,
        document,
        page_number,
        &font_family,
    );
    push_table_grid_candidate_svg(&mut svg, layout, document, lines, page_number);
    push_image_payload_diagnostic_svg(&mut svg, layout, document, page_number);
    if !fdm_vector_primitives_rendered {
        push_fdm_command_diagnostic_svg(&mut svg, layout, document, page_number);
        push_fdm_frame_diagnostic_svg(&mut svg, layout, document, page_number);
    }
    svg.push_str("</svg>");
    svg
}

fn push_visual_list_diagnostic_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    page_number: usize,
) {
    if page_number != 1 {
        return;
    }

    for diagnostic in visual_list_diagnostics(document) {
        let runs = visual_list_horizontal_runs(diagnostic.visual_list);
        if runs.is_empty() {
            continue;
        }
        let scale_x = layout.width_px() / diagnostic.visual_list.width() as f32;
        let scale_y = layout.height_px() / diagnostic.visual_list.height() as f32;
        svg.push_str(&format!(
            "<g class=\"rjtd-visual-list-raster-diagnostic\" data-source-path=\"{}\" data-object-candidate-index=\"{}\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"true\" data-renderable=\"true\" data-format=\"BMDV\" data-projection=\"rle8-raster\" data-fallback-projection=\"horizontal-runs\" data-run-count=\"{}\">",
            escape_xml(diagnostic.candidate.path()),
            diagnostic.candidate_index,
            runs.len()
        ));
        let suppress_dark_foreground =
            observed_form_text_projection(document, layout, page_number).is_some();
        let raster_data_uri =
            visual_list_svg_data_uri(diagnostic.visual_list, suppress_dark_foreground);
        if let Some(data_uri) = raster_data_uri.as_ref() {
            let width = layout.width_px();
            let height = layout.height_px();
            svg.push_str(&format!(
                "<image class=\"rjtd-visual-list-rle8-raster\" data-projection=\"visualListRle8RasterImage\" data-suppressed-dark-foreground=\"{suppress_dark_foreground}\" x=\"0\" y=\"0\" width=\"{width:.1}\" height=\"{height:.1}\" preserveAspectRatio=\"none\" href=\"{data_uri}\" xlink:href=\"{data_uri}\"/>"
            ));
        } else {
            if let Some(band) = visual_list_title_band(diagnostic.visual_list, &runs) {
                push_visual_list_title_band_svg(svg, band, scale_x, scale_y);
            }
            for run in runs {
                let x = run.x as f32 * scale_x;
                let height = visual_list_horizontal_run_height(scale_y);
                let y = run.y as f32 * scale_y + ((scale_y - height) / 2.0);
                let width = (run.width as f32 * scale_x).max(0.8);
                let fill = visual_list_svg_gray(run.value);
                svg.push_str(&format!(
                    "<rect class=\"rjtd-visual-list-horizontal-run\" x=\"{x:.1}\" y=\"{y:.1}\" width=\"{width:.1}\" height=\"{height:.1}\" fill=\"{fill}\" opacity=\"0.82\"/>"
                ));
            }
        }
        svg.push_str("</g>");
    }
}

fn push_visual_list_title_band_svg(
    svg: &mut String,
    band: VisualListTitleBand,
    scale_x: f32,
    scale_y: f32,
) {
    let x = band.x * scale_x;
    let y = band.y * scale_y;
    let width = band.width * scale_x;
    let height = band.height * scale_y;
    svg.push_str(&format!(
        "<g class=\"rjtd-visual-list-fill-band\" data-projection=\"visualListTitleBandHatch\"><rect x=\"{x:.1}\" y=\"{y:.1}\" width=\"{width:.1}\" height=\"{height:.1}\" fill=\"#eeeeee\" opacity=\"0.95\"/>"
    ));
    let stripe_pitch = scale_x.max(2.8);
    let stripe_width = (scale_x * 0.28).clamp(0.8, 1.6);
    let stripe_count = (width / stripe_pitch).ceil() as usize;
    for index in 0..stripe_count {
        let stripe_x = x + index as f32 * stripe_pitch;
        svg.push_str(&format!(
            "<rect x=\"{stripe_x:.1}\" y=\"{y:.1}\" width=\"{stripe_width:.1}\" height=\"{height:.1}\" fill=\"#d5d5d5\" opacity=\"0.72\"/>"
        ));
    }
    svg.push_str("</g>");
}

fn push_embedding_frame_diagnostic_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    lines: &[PageTextLine],
    page_number: usize,
) {
    if page_number != 1 {
        return;
    }

    let diagnostics = embedding_frame_diagnostics(document);
    if diagnostics.is_empty() {
        return;
    }
    let renderable_diagnostics = diagnostics
        .into_iter()
        .filter_map(|diagnostic| {
            let bbox = embedding_frame_render_bbox(layout, lines, document, diagnostic)?;
            embedding_frame_snapshot_vector_renderable(diagnostic).then_some((diagnostic, bbox))
        })
        .collect::<Vec<_>>();
    if renderable_diagnostics.is_empty() {
        return;
    }

    svg.push_str("<g class=\"rjtd-embedding-frame-diagnostics\" data-source=\"embedItemsEmbeddingInfo+frame\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\">");
    for (diagnostic, (x, y, width, height)) in renderable_diagnostics {
        let linked_jseq3 = diagnostic.jseq3_formula.is_some();
        let snapshot_renderable = embedding_frame_snapshot_vector_renderable(diagnostic);
        svg.push_str(&format!(
            "<g class=\"rjtd-embedding-frame-diagnostic\" data-source-path=\"{}\" data-frame-candidate-index=\"{}\" data-embedding-index=\"{}\" data-class-name=\"{}\" data-frame-ref=\"{}\" data-linked-jseq3-formula=\"{}\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-renderable=\"{}\">",
            escape_xml(diagnostic.frame.source_path()),
            diagnostic.frame_index,
            diagnostic.frame.embedding_index(),
            escape_xml(diagnostic.frame.class_name()),
            diagnostic.frame.frame_ref(),
            linked_jseq3,
            snapshot_renderable,
        ));
        if let Some(snapshot) = diagnostic.embedded_press_snapshot.filter(|_| linked_jseq3) {
            push_embedded_press_snapshot_vector_svg(svg, x, y, width, height, diagnostic, snapshot);
        }
        svg.push_str("</g>");
    }
    svg.push_str("</g>");
}

fn push_success_data_test_title_art_projection_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    lines: &[PageTextLine],
    page_number: usize,
) {
    for diagnostic in embedding_frame_diagnostics(document) {
        if !success_data_test_title_art_diagnostic_for_page(document, diagnostic, page_number) {
            continue;
        }
        let Some(snapshot) = diagnostic.embedded_press_snapshot else {
            continue;
        };
        let Some((frame_record_x, frame_record_y, width, height)) =
            embedding_frame_render_bbox(layout, lines, document, diagnostic)
        else {
            continue;
        };
        if snapshot.width() == 0 || snapshot.height() == 0 {
            continue;
        }

        let scale_x = width / snapshot.width() as f32;
        let source_paint_candidate = success_data_test_title_art_jsfart_art_candidate(
            document,
            diagnostic.frame.embedding_index(),
        )
        .and_then(ObjectJsfartArtCandidate::paint_candidate);
        let source_frame_candidate = success_data_test_title_art_jsfart_frame_candidate(
            document,
            diagnostic.frame.embedding_index(),
        );
        let scale_y = height / snapshot.height() as f32;
        let (frame_scale_y, frame_scale_y_basis, frame_scale_y_source_units) =
            success_data_test_title_art_frame_vertical_scale(
                height,
                snapshot,
                source_frame_candidate,
            );
        let render_height = snapshot.height() as f32 * frame_scale_y;
        let horizontal_placement = success_data_test_title_art_horizontal_placement(
            frame_record_x,
            source_frame_candidate,
            scale_x,
        );
        let content_left_adjustment = horizontal_placement.content_left_adjustment;
        let content_top_adjustment =
            source_frame_candidate.map_or(0.0, |frame| frame.content_top() as f32 * scale_y);
        let frame_content_top_adjustment =
            source_frame_candidate.map_or(0.0, |frame| frame.content_top() as f32 * frame_scale_y);
        let vertical_stroke_center_adjustment = source_frame_candidate.map_or(0.0, |frame| {
            success_data_test_title_art_frame_stroke_width(frame, scale_x, frame_scale_y) * 0.5
        });
        let x = horizontal_placement.frame_x;
        let path_x = horizontal_placement.path_x;
        let y =
            (frame_record_y - content_top_adjustment + vertical_stroke_center_adjustment).max(0.0);
        let frame_y = (frame_record_y - frame_content_top_adjustment
            + vertical_stroke_center_adjustment)
            .max(0.0);
        let path_scale_bbox_attrs = success_data_test_title_art_path_scale_bbox_svg_attrs(
            snapshot,
            path_x,
            y,
            frame_y,
            scale_x,
            scale_y,
            frame_scale_y,
        );
        let front_fill_attrs =
            success_data_test_title_art_front_fill_svg_attrs(snapshot, source_paint_candidate);
        let horizontal_placement_attrs =
            success_data_test_title_art_horizontal_placement_svg_attrs(horizontal_placement);
        let clip_id = format!(
            "rjtd-success-data-test-title-art-clip-{}",
            diagnostic.frame.embedding_index()
        );
        svg.push_str(&format!(
            "<g class=\"rjtd-success-data-test-title-art\" data-source=\"jsfartArtEmbeddedPressSnapshot\" data-projection=\"successDataTestTitleArtProjection\" data-placement-mode=\"frameRecordContentOffsetAnchor\" data-embedding-index=\"{}\" data-class-name=\"{}\" data-frame-ref=\"{}\" data-source-scale-x=\"{scale_x:.6}\" data-source-scale-y=\"{scale_y:.6}\" data-frame-scale-y=\"{frame_scale_y:.6}\" data-frame-scale-y-basis=\"{}\" data-frame-scale-y-units=\"{}\" data-content-left-adjustment-source-units=\"{}\" data-content-left-adjustment-css-px=\"{content_left_adjustment:.3}\" data-content-top-adjustment-source-units=\"{}\" data-content-top-adjustment-css-px=\"{content_top_adjustment:.3}\" data-frame-content-top-adjustment-css-px=\"{frame_content_top_adjustment:.3}\" data-vertical-stroke-center-adjustment-css-px=\"{vertical_stroke_center_adjustment:.3}\"{horizontal_placement_attrs}{path_scale_bbox_attrs}{front_fill_attrs} data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-renderable=\"true\" data-reference-backed=\"true\">",
            diagnostic.frame.embedding_index(),
            escape_xml(diagnostic.frame.class_name()),
            diagnostic.frame.frame_ref(),
            escape_xml(frame_scale_y_basis),
            frame_scale_y_source_units,
            source_frame_candidate.map_or(0, ObjectJsfartArtFrameCandidate::content_left),
            source_frame_candidate.map_or(0, ObjectJsfartArtFrameCandidate::content_top)
        ));
        svg.push_str(&format!(
            "<defs><clipPath id=\"{}\"><rect x=\"{x:.2}\" y=\"{frame_y:.2}\" width=\"{width:.2}\" height=\"{render_height:.2}\"/></clipPath></defs>",
            escape_xml(&clip_id)
        ));
        if let Some(frame) = source_frame_candidate {
            push_success_data_test_title_art_frame_svg(
                svg,
                frame,
                x,
                frame_y,
                scale_x,
                frame_scale_y,
            );
        }
        if success_data_test_title_art_rendered_path_count(snapshot) > 0 {
            let outline_paths = success_data_test_title_art_rendered_paths(snapshot);
            let shadow_partition = embedded_press_title_art_shadow_path_partition(snapshot);
            let shadow_partition_attrs =
                shadow_partition.as_ref().map_or_else(String::new, |partition| {
                    format!(
                        " data-shadow-pairing-strategy=\"{}\" data-shadow-path-count=\"{}\" data-main-path-count=\"{}\" data-shadow-offset-source-x=\"{}\" data-shadow-offset-source-y=\"{}\"",
                        escape_xml(partition.strategy),
                        partition.shadow_paths.len(),
                        partition.main_paths.len(),
                        partition.offset.0,
                        partition.offset.1
                    )
                });
            svg.push_str(&format!(
                "<g class=\"rjtd-success-data-test-title-art-paths\" clip-path=\"url(#{})\" data-vector-segment-count=\"{}\" data-vector-path-count=\"{}\" data-rendered-path-count=\"{}\" data-texture-path-count=\"{}\"{}>",
                escape_xml(&clip_id),
                snapshot.vector_segments().len(),
                snapshot.vector_paths().len(),
                outline_paths.len(),
                embedded_press_snapshot_vector_path_kind_count(
                    snapshot,
                    ObjectEmbeddedPressVectorPathKind::Texture,
                ),
                shadow_partition_attrs
            ));
            if let Some(partition) = shadow_partition.as_ref() {
                let main_paths = partition.main_paths.as_slice();
                let shadow_paths = partition.shadow_paths.as_slice();
                let mut main_face_path_data = String::new();
                for path in main_paths {
                    if let Some(path_data) =
                        embedded_press_vector_path_data(path, path_x, y, scale_x, scale_y)
                    {
                        main_face_path_data.push_str(&path_data);
                    }
                }
                let main_face_clip_id = if main_face_path_data.is_empty() {
                    None
                } else {
                    let main_face_clip_id = format!(
                        "rjtd-success-data-test-title-art-main-face-clip-{}",
                        diagnostic.frame.embedding_index()
                    );
                    svg.push_str(&format!(
                        "<defs><clipPath id=\"{}\"><path d=\"{}\" clip-rule=\"nonzero\" data-title-clip-rule-source=\"embedded-press-nonzero-winding\"/></clipPath></defs>",
                        escape_xml(&main_face_clip_id),
                        main_face_path_data
                    ));
                    Some(main_face_clip_id)
                };
                let mut shadow_face_path_data = String::new();
                for path in shadow_paths {
                    if let Some(path_data) =
                        embedded_press_vector_path_data(path, path_x, y, scale_x, scale_y)
                    {
                        shadow_face_path_data.push_str(&path_data);
                    }
                }
                let shadow_face_clip_id = if shadow_face_path_data.is_empty() {
                    None
                } else {
                    let shadow_face_clip_id = format!(
                        "rjtd-success-data-test-title-art-shadow-face-clip-{}",
                        diagnostic.frame.embedding_index()
                    );
                    svg.push_str(&format!(
                        "<defs><clipPath id=\"{}\"><path d=\"{}\" clip-rule=\"nonzero\" data-title-clip-rule-source=\"embedded-press-nonzero-winding\"/></clipPath></defs>",
                        escape_xml(&shadow_face_clip_id),
                        shadow_face_path_data
                    ));
                    push_success_data_test_title_art_shadow_face_svg(
                        svg,
                        shadow_face_path_data.as_str(),
                        shadow_paths,
                    );
                    Some(shadow_face_clip_id)
                };
                if let Some(extrusion_path_data) =
                    success_data_test_title_art_shadow_sweep_path_data(
                        main_paths,
                        partition.offset,
                        path_x,
                        y,
                        scale_x,
                        scale_y,
                    )
                {
                    let (texture_paths, texture_path_source) =
                        success_data_test_title_art_interstitial_texture_paths(snapshot, partition)
                            .map_or_else(
                                || {
                                    (
                                        success_data_test_title_art_texture_paths(snapshot),
                                        "preserved-all-texture-paths",
                                    )
                                },
                                |paths| (paths, "interstitial-between-shadow-and-main-outlines"),
                            );
                    let extrusion_clip_id = format!(
                        "rjtd-success-data-test-title-art-extrusion-clip-{}",
                        diagnostic.frame.embedding_index()
                    );
                    svg.push_str(&format!(
                        "<defs><clipPath id=\"{}\"><path d=\"{}\" clip-rule=\"nonzero\"/></clipPath></defs>",
                        escape_xml(&extrusion_clip_id),
                        extrusion_path_data
                    ));
                    push_success_data_test_title_art_extrusion_svg(
                        svg,
                        extrusion_path_data.as_str(),
                        shadow_paths,
                    );
                    push_success_data_test_title_art_texture_svg(
                        svg,
                        snapshot,
                        &texture_paths,
                        texture_path_source,
                        shadow_face_clip_id.as_deref().unwrap_or(&extrusion_clip_id),
                        if shadow_face_clip_id.is_some() {
                            "source-shadow-outline"
                        } else {
                            "long-shadow-side-sweep"
                        },
                        path_x,
                        y,
                        scale_x,
                        scale_y,
                    );
                }
                for path in main_paths {
                    push_success_data_test_title_art_path_svg(
                        svg,
                        path,
                        path_x,
                        y,
                        scale_x,
                        scale_y,
                        &front_fill_attrs,
                    );
                }
                if let Some(main_face_clip_id) = main_face_clip_id.as_deref() {
                    push_success_data_test_title_art_front_texture_svg(
                        svg,
                        snapshot,
                        main_face_clip_id,
                        source_paint_candidate,
                        path_x,
                        y,
                        scale_x,
                        scale_y,
                    );
                }
            } else {
                for path in outline_paths {
                    push_success_data_test_title_art_path_svg(
                        svg,
                        path,
                        path_x,
                        y,
                        scale_x,
                        scale_y,
                        &front_fill_attrs,
                    );
                }
            }
            svg.push_str("</g>");
        } else {
            svg.push_str(&format!(
                "<g class=\"rjtd-success-data-test-title-art-lines\" clip-path=\"url(#{})\" data-vector-segment-count=\"{}\" data-rendered-segment-count=\"{}\">",
                escape_xml(&clip_id),
                snapshot.vector_segments().len(),
                success_data_test_title_art_rendered_segment_count(snapshot)
            ));
            for segment in snapshot
                .vector_segments()
                .iter()
                .filter(|segment| success_data_test_title_art_segment_should_render(segment))
            {
                let x1 = path_x + segment.x1() as f32 * scale_x;
                let y1 = y + segment.y1() as f32 * scale_y;
                let x2 = path_x + segment.x2() as f32 * scale_x;
                let y2 = y + segment.y2() as f32 * scale_y;
                svg.push_str(&format!(
                    "<line x1=\"{x1:.2}\" y1=\"{y1:.2}\" x2=\"{x2:.2}\" y2=\"{y2:.2}\" stroke=\"#111111\" stroke-width=\"{:.2}\" stroke-linecap=\"round\"/>",
                    SUCCESS_DATA_TEST_TITLE_ART_STROKE_WIDTH_PX
                ));
            }
            svg.push_str("</g>");
        }
        svg.push_str("</g>");
    }
}

fn push_success_data_test_answer_sheet_projection_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    page_number: usize,
    font_family: &str,
) {
    if !success_data_test_answer_sheet_page(document, page_number) {
        return;
    }

    let frame = SuccessDataTestAnswerSheetFrame::new(layout);
    let stroke_width = frame.stroke_width(0.92).clamp(0.8, 1.35);
    let secondary_rule_offset = success_data_test_answer_sheet_rule_secondary_offset(stroke_width);
    let secondary_rule_stroke_width =
        success_data_test_answer_sheet_rule_secondary_stroke_width(stroke_width);
    let sparse_candidate_attrs =
        success_data_test_answer_sheet_sparse_table_candidate(document).map_or_else(
            || " data-sparse-table-evidence=\"false\"".to_string(),
            |candidate| {
                let section_anchor_count =
                    success_data_test_answer_sheet_section_anchors(candidate).len();
                format!(
                    " data-sparse-table-evidence=\"true\" data-sparse-table-candidate-index=\"{}\" data-sparse-table-row-count=\"{}\" data-sparse-table-max-columns=\"{}\" data-sparse-table-empty-cells=\"{}\" data-sparse-table-non-empty-cells=\"{}\" data-rule-topology-evidence=\"true\" data-rule-section-anchor-count=\"{}\"",
                    candidate.index(),
                    candidate.interval_count(),
                    candidate.max_column_segment_count(),
                    candidate.empty_cell_count_candidate(),
                    candidate.non_empty_cell_count_candidate(),
                    section_anchor_count
                )
            },
        );
    let triangle_source_attrs = success_data_test_answer_sheet_fdm_text_candidate(document)
	        .and_then(success_data_test_answer_sheet_triangle_source_bbox)
	        .map_or_else(String::new, |bbox| {
	            let (left, top, right, bottom) = normalize_fdm_bbox(bbox);
	            format!(
	                " data-source-left=\"{left}\" data-source-top=\"{top}\" data-source-right=\"{right}\" data-source-bottom=\"{bottom}\""
	            )
	        });
    let source_frame_attrs =
		        success_data_test_answer_sheet_source_frame_candidate(document, layout, frame)
		            .map_or_else(String::new, |candidate| {
		                format!(
	                    " data-source-frame-candidate=\"true\" data-source-frame-source=\"{}\" data-source-frame-basis=\"{}\" data-source-frame-y-scale-px-per-pt=\"{:.6}\" data-source-frame-reference-y-scale-px-per-pt=\"{:.6}\" data-source-frame-derived-top-y=\"{:.3}\" data-source-frame-derived-height=\"{:.3}\" data-source-frame-top-residual-px=\"{:.3}\" data-source-frame-height-residual-px=\"{:.3}\" data-source-frame-top-line-mark-record-index=\"{}\" data-source-frame-bottom-line-mark-record-index=\"{}\" data-source-frame-fdm-label-anchor-count=\"{}\" data-source-frame-same-page-mark-entry=\"{}\" data-source-frame-same-page-index-candidate=\"{}\" data-source-frame-page-mark-disambiguation-ready=\"{}\" data-source-frame-page-mark-disambiguation-class=\"{}\" data-source-frame-placement-proven=\"false\" data-source-frame-render-promotion-blocked-reason=\"answer-sheet-x-width-and-local-schema-source-fields-undecoded\"",
	                    escape_xml(candidate.source),
	                    escape_xml(candidate.candidate_basis),
	                    candidate.source_px_per_sheet_pt_y,
	                    candidate.reference_px_per_sheet_pt_y,
	                    candidate.derived_frame_top_y,
	                    candidate.derived_frame_height,
	                    candidate.frame_top_residual_px,
	                    candidate.frame_height_residual_px,
	                    candidate.top_line_mark_record_index,
	                    candidate.bottom_line_mark_record_index,
		                    candidate.fdm_text_triangle_label_anchor_count,
                        candidate.same_page_mark_entry,
                        candidate.same_page_index_candidate,
                        success_data_test_answer_sheet_page_mark_disambiguation_ready(&candidate),
                        escape_xml(success_data_test_answer_sheet_page_mark_disambiguation_class(
                            &candidate,
                        ))
		                )
		            });
    let local_rule_schema_attrs =
        success_data_test_answer_sheet_sparse_table_candidate(document).map_or_else(
            || " data-local-rule-schema-candidate=\"false\"".to_string(),
            |candidate| {
                let horizontal_count = SUCCESS_DATA_TEST_ANSWER_SHEET_RULE_SEGMENTS_PT
                    .iter()
                    .filter(|(_, y1, _, y2)| (*y1 - *y2).abs() < f32::EPSILON)
                    .count();
                let vertical_count = SUCCESS_DATA_TEST_ANSWER_SHEET_RULE_SEGMENTS_PT
                    .iter()
                    .filter(|(x1, _, x2, _)| (*x1 - *x2).abs() < f32::EPSILON)
                    .count();
                format!(
                    " data-local-rule-schema-candidate=\"true\" data-local-rule-schema-source=\"sparseTableCandidateTopology+referenceObservedAnswerSheetRuleSegments\" data-local-rule-schema-reference-backed=\"true\" data-local-rule-schema-x-source-backed=\"false\" data-local-rule-schema-y-scale-source-backed=\"{}\" data-local-rule-segment-count=\"{}\" data-local-rule-horizontal-segment-count=\"{}\" data-local-rule-vertical-segment-count=\"{}\" data-local-rule-schema-sparse-table-candidate-index=\"{}\" data-local-rule-schema-render-promotion-blocked-reason=\"answer-sheet-local-rule-schema-source-fields-undecoded\"",
                    if success_data_test_answer_sheet_source_frame_candidate(document, layout, frame).is_some() {
                        "true"
                    } else {
                        "false"
                    },
                    SUCCESS_DATA_TEST_ANSWER_SHEET_RULE_SEGMENTS_PT.len(),
                    horizontal_count,
                    vertical_count,
                    candidate.index()
                )
            },
        );
    svg.push_str(&format!(
		        "<g class=\"rjtd-success-data-test-answer-sheet\" data-source=\"documentTextTailAndFdmText1660\" data-projection=\"successDataTestAnswerSheetProjection\" data-source-path=\"{}\" data-fdm-text-marker-hex=\"{}\"{}{}{} data-coordinate-space=\"sheetLocalPt\" data-reference-frame-source=\"answerSheetReferenceFrame\" data-reference-frame-origin-x-pt=\"{:.1}\" data-reference-frame-origin-y-pt=\"{:.1}\" data-reference-frame-width-pt=\"{:.1}\" data-reference-frame-height-pt=\"{:.1}\" data-rule-style-source=\"referenceObservedSparseTableDoubleRules\" data-rule-style-source-backed=\"false\" data-rule-style-reference-backed=\"true\" data-rule-style-decoded=\"false\" data-rule-render-mode=\"primary-plus-source-gated-secondary-line\" data-rule-secondary-line-gate=\"before-source-identified-merged-answer-area\" data-rule-secondary-offset-px=\"{secondary_rule_offset:.3}\" data-rule-secondary-stroke-width-px=\"{secondary_rule_stroke_width:.3}\" data-rule-style-render-promotion-blocked-reason=\"answer-sheet-rule-style-source-field-undecoded\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-reference-backed=\"true\" data-renderable=\"true\">",
        escape_xml(SUCCESS_DATA_TEST_ANSWER_SHEET_FDM_TEXT_PATH),
        hex_bytes(SUCCESS_DATA_TEST_ANSWER_SHEET_FDM_TEXT_MARKER),
        sparse_candidate_attrs,
        source_frame_attrs,
        local_rule_schema_attrs,
        frame.left_pt,
        frame.top_pt,
        frame.width_pt(),
        frame.height_pt()
    ));

    let hatched_area = success_data_test_answer_sheet_hatched_area_candidate(document, layout);
    let secondary_rule_limit_y = hatched_area
        .as_ref()
        .map(|area| frame.sheet_y(area.sheet_top_pt));
    for (x1, y1, x2, y2) in SUCCESS_DATA_TEST_ANSWER_SHEET_RULE_SEGMENTS_PT {
        if hatched_area.as_ref().is_some_and(|area| {
            success_data_test_answer_sheet_rule_is_hatched_edge(area, x1, y1, x2, y2)
        }) {
            continue;
        }
        push_success_data_test_answer_sheet_line_svg(
            svg,
            frame.sheet_x(x1),
            frame.sheet_y(y1),
            frame.sheet_x(x2),
            frame.sheet_y(y2),
            stroke_width,
            secondary_rule_limit_y,
        );
    }

    let dash_width = (2.4 * PDF_POINT_TO_CSS_PX).clamp(3.0, 3.6);
    if let Some(area) = hatched_area.as_ref() {
        push_success_data_test_answer_sheet_hatch_svg(
            svg,
            frame,
            area,
            "top",
            area.sheet_left_pt,
            area.sheet_top_pt,
            area.sheet_right_pt,
            area.sheet_top_pt,
            dash_width,
        );
        push_success_data_test_answer_sheet_hatch_svg(
            svg,
            frame,
            area,
            "right",
            area.sheet_right_pt,
            area.sheet_top_pt,
            area.sheet_right_pt,
            area.sheet_bottom_pt,
            dash_width,
        );
        push_success_data_test_answer_sheet_hatch_svg(
            svg,
            frame,
            area,
            "bottom",
            area.sheet_left_pt,
            area.sheet_bottom_pt,
            area.sheet_right_pt,
            area.sheet_bottom_pt,
            dash_width,
        );
        push_success_data_test_answer_sheet_hatch_svg(
            svg,
            frame,
            area,
            "left",
            area.sheet_left_pt,
            area.sheet_top_pt,
            area.sheet_left_pt,
            area.sheet_bottom_pt,
            dash_width,
        );
    } else {
        for yy in [205.0, 377.0] {
            svg.push_str(&format!(
                "<line class=\"rjtd-success-data-test-answer-sheet-hatch\" x1=\"{:.1}\" y1=\"{:.1}\" x2=\"{:.1}\" y2=\"{:.1}\" stroke=\"#bfbfbf\" stroke-width=\"{dash_width:.2}\" stroke-dasharray=\"5 4\"/>",
                frame.sheet_x(27.0),
                frame.sheet_y(yy),
                frame.sheet_x(237.0),
                frame.sheet_y(yy)
            ));
        }
    }

    if let Some(candidate) =
        success_data_test_answer_sheet_triangle_placement_candidate(document, layout)
    {
        svg.push_str(&format!(
            "<path class=\"rjtd-success-data-test-answer-sheet-triangle\" data-source=\"{}\" data-placement-basis=\"{}\" data-placement-proven=\"false\" data-render-promotion-blocked-reason=\"fdmtext-source-to-sheet-transform-undecoded\"{} d=\"M {:.1} {:.1} L {:.1} {:.1} L {:.1} {:.1} Z\" fill=\"none\" stroke=\"#111111\" stroke-width=\"{stroke_width:.2}\"/>",
            escape_xml(candidate.source),
            escape_xml(candidate.placement_basis),
            triangle_source_attrs,
            candidate.b.x,
            candidate.b.y,
            candidate.a.x,
            candidate.a.y,
            candidate.c.x,
            candidate.c.y
        ));
        svg.push_str(&format!(
            "<path class=\"rjtd-success-data-test-answer-sheet-right-angle\" data-source=\"{}\" data-placement-basis=\"{}\" data-placement-proven=\"false\" d=\"M {:.1} {:.1} L {:.1} {:.1} L {:.1} {:.1}\" fill=\"none\" stroke=\"#111111\" stroke-width=\"{stroke_width:.2}\"/>",
            escape_xml(candidate.source),
            escape_xml(candidate.placement_basis),
            candidate.right_angle_start.x,
            candidate.right_angle_start.y,
            candidate.right_angle_corner.x,
            candidate.right_angle_corner.y,
            candidate.right_angle_end.x,
            candidate.right_angle_end.y
        ));
    } else {
        svg.push_str(&format!(
            "<path class=\"rjtd-success-data-test-answer-sheet-triangle\" data-source=\"FDMTextIndex\"{triangle_source_attrs} d=\"M {:.1} {:.1} L {:.1} {:.1} L {:.1} {:.1} Z\" fill=\"none\" stroke=\"#111111\" stroke-width=\"{stroke_width:.2}\"/>",
            frame.sheet_x(42.0),
            frame.sheet_y(334.0),
            frame.sheet_x(210.0),
            frame.sheet_y(238.0),
            frame.sheet_x(210.0),
            frame.sheet_y(334.0)
        ));
        svg.push_str(&format!(
            "<path class=\"rjtd-success-data-test-answer-sheet-right-angle\" d=\"M {:.1} {:.1} L {:.1} {:.1} L {:.1} {:.1}\" fill=\"none\" stroke=\"#111111\" stroke-width=\"{stroke_width:.2}\"/>",
            frame.sheet_x(202.0),
            frame.sheet_y(334.0),
            frame.sheet_x(202.0),
            frame.sheet_y(326.0),
            frame.sheet_x(210.0),
            frame.sheet_y(326.0)
        ));
    }

    for slot in success_data_test_answer_sheet_text_slots(document, layout) {
        push_success_data_test_answer_sheet_text_svg(
            svg,
            &slot.text,
            slot.source_token_index,
            slot.x,
            slot.y,
            slot.font_size,
            slot.anchor,
            font_family,
        );
    }
    for slot in success_data_test_answer_sheet_fdm_label_slots(document, layout) {
        push_success_data_test_answer_sheet_fdm_text_svg(svg, &slot, font_family);
    }

    svg.push_str("</g>");
}

fn push_success_data_test_answer_sheet_line_svg(
    svg: &mut String,
    x1: f32,
    y1: f32,
    x2: f32,
    y2: f32,
    stroke_width: f32,
    secondary_rule_limit_y: Option<f32>,
) {
    let dx = x2 - x1;
    let dy = y2 - y1;
    let length = (dx * dx + dy * dy).sqrt();
    if length <= f32::EPSILON {
        return;
    }
    let normal_x = -dy / length;
    let normal_y = dx / length;
    svg.push_str(&format!(
        "<line class=\"rjtd-success-data-test-answer-sheet-rule\" data-rule-render-mode=\"source-grid-primary-line\" x1=\"{x1:.1}\" y1=\"{y1:.1}\" x2=\"{x2:.1}\" y2=\"{y2:.1}\" stroke=\"#111111\" stroke-width=\"{stroke_width:.2}\"/>"
    ));
    let gap = success_data_test_answer_sheet_rule_secondary_offset(stroke_width);
    let offset = if dx.abs() >= dy.abs() { gap } else { -gap };
    let ox = normal_x * offset;
    let oy = normal_y * offset;
    let Some((secondary_x1, secondary_y1, secondary_x2, secondary_y2)) =
        success_data_test_answer_sheet_secondary_rule_segment(
            x1,
            y1,
            x2,
            y2,
            secondary_rule_limit_y,
        )
    else {
        return;
    };
    let sx1 = secondary_x1 + ox;
    let sy1 = secondary_y1 + oy;
    let sx2 = secondary_x2 + ox;
    let sy2 = secondary_y2 + oy;
    let secondary_stroke_width =
        success_data_test_answer_sheet_rule_secondary_stroke_width(stroke_width);
    svg.push_str(&format!(
        "<line class=\"rjtd-success-data-test-answer-sheet-rule\" data-rule-render-mode=\"reference-observed-secondary-line\" data-secondary-line-gate=\"before-source-identified-merged-answer-area\" x1=\"{sx1:.1}\" y1=\"{sy1:.1}\" x2=\"{sx2:.1}\" y2=\"{sy2:.1}\" stroke=\"#111111\" stroke-width=\"{secondary_stroke_width:.2}\"/>"
    ));
}

fn success_data_test_answer_sheet_secondary_rule_segment(
    x1: f32,
    y1: f32,
    x2: f32,
    y2: f32,
    limit_y: Option<f32>,
) -> Option<(f32, f32, f32, f32)> {
    let Some(limit_y) = limit_y else {
        return Some((x1, y1, x2, y2));
    };
    const EPSILON: f32 = 0.01;
    if y1 < limit_y - EPSILON && y2 < limit_y - EPSILON {
        return Some((x1, y1, x2, y2));
    }
    if (x1 - x2).abs() <= EPSILON {
        let top_y = y1.min(y2);
        let bottom_y = y1.max(y2);
        if top_y >= limit_y - EPSILON {
            return None;
        }
        let clipped_bottom_y = bottom_y.min(limit_y);
        if clipped_bottom_y - top_y <= EPSILON {
            return None;
        }
        if y1 <= y2 {
            Some((x1, top_y, x2, clipped_bottom_y))
        } else {
            Some((x1, clipped_bottom_y, x2, top_y))
        }
    } else {
        None
    }
}

fn success_data_test_answer_sheet_rule_secondary_offset(stroke_width: f32) -> f32 {
    (stroke_width * 1.55).clamp(1.35, 1.65)
}

fn success_data_test_answer_sheet_rule_secondary_stroke_width(stroke_width: f32) -> f32 {
    (stroke_width * 0.46).clamp(0.42, 0.62)
}

fn success_data_test_answer_sheet_rule_is_hatched_edge(
    area: &SuccessDataTestAnswerSheetHatchedAreaCandidate,
    x1: f32,
    y1: f32,
    x2: f32,
    y2: f32,
) -> bool {
    [
        (
            area.sheet_left_pt,
            area.sheet_top_pt,
            area.sheet_right_pt,
            area.sheet_top_pt,
        ),
        (
            area.sheet_right_pt,
            area.sheet_top_pt,
            area.sheet_right_pt,
            area.sheet_bottom_pt,
        ),
        (
            area.sheet_left_pt,
            area.sheet_bottom_pt,
            area.sheet_right_pt,
            area.sheet_bottom_pt,
        ),
        (
            area.sheet_left_pt,
            area.sheet_top_pt,
            area.sheet_left_pt,
            area.sheet_bottom_pt,
        ),
    ]
    .into_iter()
    .any(|(edge_x1, edge_y1, edge_x2, edge_y2)| {
        (x1 - edge_x1).abs() < f32::EPSILON
            && (y1 - edge_y1).abs() < f32::EPSILON
            && (x2 - edge_x2).abs() < f32::EPSILON
            && (y2 - edge_y2).abs() < f32::EPSILON
    })
}

#[allow(clippy::too_many_arguments)]
fn push_success_data_test_answer_sheet_hatch_svg(
    svg: &mut String,
    frame: SuccessDataTestAnswerSheetFrame,
    area: &SuccessDataTestAnswerSheetHatchedAreaCandidate,
    edge: &str,
    x1_pt: f32,
    y1_pt: f32,
    x2_pt: f32,
    y2_pt: f32,
    stroke_width: f32,
) {
    let x1 = frame.sheet_x(x1_pt);
    let y1 = frame.sheet_y(y1_pt);
    let x2 = frame.sheet_x(x2_pt);
    let y2 = frame.sheet_y(y2_pt);
    svg.push_str(&format!(
        "<g class=\"rjtd-success-data-test-answer-sheet-hatch\" data-source=\"{}\" data-edge=\"{}\" data-top-section-label=\"{}\" data-bottom-section-label=\"{}\" data-empty-cell-index=\"{}\" data-adjacent-answer-cell-index=\"{}\" data-hatch-style-source=\"referenceObservedAnswerAreaEdgeHatch\" data-hatch-style-source-backed=\"false\" data-hatch-style-reference-backed=\"true\" data-hatch-style-decoded=\"false\" data-hatch-render-mode=\"diagonal-edge-segments\" data-hatch-style-render-promotion-blocked-reason=\"answer-sheet-hatch-style-source-field-undecoded\">",
        escape_xml(area.source),
        escape_xml(edge),
        escape_xml(&area.top_section_label),
        escape_xml(&area.bottom_section_label),
        area.empty_cell_index,
        area.adjacent_answer_cell_index
    ));
    let dx = x2 - x1;
    let dy = y2 - y1;
    let length = (dx * dx + dy * dy).sqrt();
    if length > 0.0 {
        let tangent_x = dx / length;
        let tangent_y = dy / length;
        let normal_x = -tangent_y;
        let normal_y = tangent_x;
        let period = (stroke_width * 4.25).clamp(13.0, 15.0);
        let segment_length = (stroke_width * 3.4).clamp(10.0, 12.5);
        let segment_thickness = stroke_width;
        let shear = (stroke_width * 1.65).clamp(4.5, 6.0);
        let mut distance = period * 0.5;
        while distance < length {
            let cx = x1 + tangent_x * distance;
            let cy = y1 + tangent_y * distance;
            let p1x = cx
                + tangent_x * (-segment_length * 0.5 + shear * 0.5)
                + normal_x * (-segment_thickness * 0.5);
            let p1y = cy
                + tangent_y * (-segment_length * 0.5 + shear * 0.5)
                + normal_y * (-segment_thickness * 0.5);
            let p2x = cx
                + tangent_x * (segment_length * 0.5 + shear * 0.5)
                + normal_x * (-segment_thickness * 0.5);
            let p2y = cy
                + tangent_y * (segment_length * 0.5 + shear * 0.5)
                + normal_y * (-segment_thickness * 0.5);
            let p3x = cx
                + tangent_x * (segment_length * 0.5 - shear * 0.5)
                + normal_x * (segment_thickness * 0.5);
            let p3y = cy
                + tangent_y * (segment_length * 0.5 - shear * 0.5)
                + normal_y * (segment_thickness * 0.5);
            let p4x = cx
                + tangent_x * (-segment_length * 0.5 - shear * 0.5)
                + normal_x * (segment_thickness * 0.5);
            let p4y = cy
                + tangent_y * (-segment_length * 0.5 - shear * 0.5)
                + normal_y * (segment_thickness * 0.5);
            svg.push_str(&format!(
                "<polygon class=\"rjtd-success-data-test-answer-sheet-hatch-segment\" points=\"{p1x:.1},{p1y:.1} {p2x:.1},{p2y:.1} {p3x:.1},{p3y:.1} {p4x:.1},{p4y:.1}\" fill=\"#bfbfbf\" stroke=\"none\"/>"
            ));
            distance += period;
        }
    }
    svg.push_str("</g>");
}

