fn embedded_press_vector_path_offset_delta(
    main_path: &ObjectEmbeddedPressVectorPathCandidate,
    shadow_path: &ObjectEmbeddedPressVectorPathCandidate,
) -> Option<(i32, i32)> {
    let main_bbox = embedded_press_vector_path_sampled_source_bbox(
        main_path,
        SUCCESS_DATA_TEST_TITLE_ART_FACE_CURVE_SAMPLES,
    )
    .or_else(|| embedded_press_vector_path_source_bbox(main_path))?;
    let shadow_bbox = embedded_press_vector_path_sampled_source_bbox(
        shadow_path,
        SUCCESS_DATA_TEST_TITLE_ART_FACE_CURVE_SAMPLES,
    )
    .or_else(|| embedded_press_vector_path_source_bbox(shadow_path))?;
    let offset_x = shadow_bbox.0 - main_bbox.0;
    let offset_y = shadow_bbox.1 - main_bbox.1;
    if offset_x == 0 && offset_y == 0 {
        return None;
    }
    Some((offset_x, offset_y))
}

fn embedded_press_vector_path_sampled_contours(
    path: &ObjectEmbeddedPressVectorPathCandidate,
    curve_samples: usize,
) -> Vec<Vec<(f32, f32)>> {
    let samples = curve_samples.max(1);
    let mut contours = Vec::new();
    let mut contour = Vec::new();
    let mut current = None;
    let mut contour_start = None;

    for command in path.commands() {
        match command {
            ObjectEmbeddedPressVectorPathCommandCandidate::MoveTo { x, y } => {
                if contour.len() > 1 {
                    contours.push(std::mem::take(&mut contour));
                } else {
                    contour.clear();
                }
                let point = (*x as f32, *y as f32);
                contour.push(point);
                current = Some(point);
                contour_start = Some(point);
            }
            ObjectEmbeddedPressVectorPathCommandCandidate::CubicTo {
                x1,
                y1,
                x2,
                y2,
                x3,
                y3,
            } => {
                let Some(start) = current else {
                    continue;
                };
                let c1 = (*x1 as f32, *y1 as f32);
                let c2 = (*x2 as f32, *y2 as f32);
                let end = (*x3 as f32, *y3 as f32);
                for step in 1..=samples {
                    let t = step as f32 / samples as f32;
                    contour.push(cubic_bezier_point(start, c1, c2, end, t));
                }
                current = Some(end);
            }
            ObjectEmbeddedPressVectorPathCommandCandidate::Close => {
                if let (Some(start), Some(last)) = (contour_start, current)
                    && ((start.0 - last.0).abs() > f32::EPSILON
                        || (start.1 - last.1).abs() > f32::EPSILON)
                {
                    contour.push(start);
                }
                if contour.len() > 1 {
                    contours.push(std::mem::take(&mut contour));
                } else {
                    contour.clear();
                }
                current = contour_start;
                contour_start = None;
            }
        }
    }
    if contour.len() > 1 {
        contours.push(contour);
    }

    contours
}

fn embedded_press_vector_path_evenodd_boundary_contours(
    path: &ObjectEmbeddedPressVectorPathCandidate,
    curve_samples: usize,
) -> Vec<Vec<(f32, f32)>> {
    embedded_press_vector_path_sampled_contours(path, curve_samples)
        .into_iter()
        .filter(|contour| {
            let area = embedded_press_sampled_contour_signed_area(contour);
            area.abs() > f32::EPSILON
        })
        .collect()
}

fn embedded_press_sampled_contour_signed_area(contour: &[(f32, f32)]) -> f32 {
    if contour.len() < 3 {
        return 0.0;
    }
    contour
        .iter()
        .zip(contour.iter().cycle().skip(1))
        .take(contour.len())
        .map(|(a, b)| a.0 * b.1 - b.0 * a.1)
        .sum::<f32>()
        * 0.5
}

fn cubic_bezier_point(
    p0: (f32, f32),
    p1: (f32, f32),
    p2: (f32, f32),
    p3: (f32, f32),
    t: f32,
) -> (f32, f32) {
    let mt = 1.0 - t;
    let mt2 = mt * mt;
    let t2 = t * t;
    (
        mt2 * mt * p0.0 + 3.0 * mt2 * t * p1.0 + 3.0 * mt * t2 * p2.0 + t2 * t * p3.0,
        mt2 * mt * p0.1 + 3.0 * mt2 * t * p1.1 + 3.0 * mt * t2 * p2.1 + t2 * t * p3.1,
    )
}

fn embedded_press_source_point_to_page(
    point: (f32, f32),
    x: f32,
    y: f32,
    scale_x: f32,
    scale_y: f32,
) -> (f32, f32) {
    (x + point.0 * scale_x, y + point.1 * scale_y)
}

fn embedded_press_vector_path_sampled_source_bbox(
    path: &ObjectEmbeddedPressVectorPathCandidate,
    curve_samples: usize,
) -> Option<(i32, i32, i32, i32)> {
    let contours = embedded_press_vector_path_sampled_contours(path, curve_samples);
    let mut min_x = f32::INFINITY;
    let mut min_y = f32::INFINITY;
    let mut max_x = f32::NEG_INFINITY;
    let mut max_y = f32::NEG_INFINITY;
    let mut has_point = false;
    for contour in contours {
        for (x, y) in contour {
            min_x = min_x.min(x);
            min_y = min_y.min(y);
            max_x = max_x.max(x);
            max_y = max_y.max(y);
            has_point = true;
        }
    }
    has_point.then(|| {
        (
            min_x.floor() as i32,
            min_y.floor() as i32,
            max_x.ceil() as i32,
            max_y.ceil() as i32,
        )
    })
}

fn embedded_press_vector_path_source_bbox(
    path: &ObjectEmbeddedPressVectorPathCandidate,
) -> Option<(i32, i32, i32, i32)> {
    let mut min_x = i32::MAX;
    let mut min_y = i32::MAX;
    let mut max_x = i32::MIN;
    let mut max_y = i32::MIN;
    let mut has_point = false;
    for command in path.commands() {
        match command {
            ObjectEmbeddedPressVectorPathCommandCandidate::MoveTo { x, y } => {
                let x = *x as i32;
                let y = *y as i32;
                min_x = min_x.min(x);
                min_y = min_y.min(y);
                max_x = max_x.max(x);
                max_y = max_y.max(y);
                has_point = true;
            }
            ObjectEmbeddedPressVectorPathCommandCandidate::CubicTo {
                x1,
                y1,
                x2,
                y2,
                x3,
                y3,
            } => {
                for (x, y) in [(*x1, *y1), (*x2, *y2), (*x3, *y3)] {
                    let x = x as i32;
                    let y = y as i32;
                    min_x = min_x.min(x);
                    min_y = min_y.min(y);
                    max_x = max_x.max(x);
                    max_y = max_y.max(y);
                    has_point = true;
                }
            }
            ObjectEmbeddedPressVectorPathCommandCandidate::Close => {}
        }
    }
    has_point.then_some((min_x, min_y, max_x, max_y))
}

